window.JIKJI_I18N["fr"]={
 "nav.arch": "Architecture",
 "nav.loop": "Boucle d'agent",
 "nav.tools": "Outils",
 "nav.orch": "Orchestration",
 "nav.memory": "Mémoire &amp; données",
 "nav.ontology": "Ontologie",
 "nav.enterprise": "Entreprise",
 "hero.sub": "Jikji est un framework d'agents modulaire qui s'exécute sous la forme d'un seul binaire Go statique — une boucle d'agent déterministe, un état d'orchestration durable, une coordination multimodèle adaptative et une gouvernance intégrée. Conçu pour les workflows agentiques à long horizon, du portable aux clusters d'entreprise.",
 "cta.start": "Commencer",
 "story.tag": "Le nom",
 "story.h2": "Nommé d'après le premier livre au monde imprimé en caractères métalliques mobiles",
 "story.p1": "<b>Jikji</b> (직지심체요절) a été imprimé en Corée en 1377 : c'est le plus ancien livre conservé imprimé en caractères métalliques mobiles, des décennies avant Gutenberg. Les caractères mobiles ont transformé l'édition exactement comme Jikji entend transformer les agents : <b>des pièces combinables, composées avec précision, pour une production fiable à grande échelle.</b>",
 "story.p2": "Chaque module porte un nom emprunté à la typographie : la <b>foundry</b> coule le runtime, le <b>type</b> habille les modèles, les <b>sorts</b> sont les outils, le <b>compositor</b> met en page les sessions, la <b>forme</b> verrouille la boucle d'agent et la <b>press</b> la diffuse au monde. Même le port par défaut est <span class=\"mono\">1377</span>.",
 "story.cap": "Jikjisimcheyojeol — le plus ancien livre subsistant imprimé en caractères métalliques mobiles. Inscrit au registre Mémoire du monde de l'UNESCO.",
 "nav.why": "Pourquoi Jikji",
 "why.h2": "Ce qui le distingue des autres frameworks d'agents",
 "why.p": "La plupart des frameworks d'agents sont des bibliothèques Python ou Node.js/TypeScript collées à une base de données vectorielle, avec des boucles opaques et une gouvernance ajoutée après coup. jikji est conçu comme une infrastructure dès le premier jour.",
 "c1.h": "Un seul binaire statique, zéro casse-tête de dépendances",
 "c1.p": "Écrit en Go et livré sous forme d'un binaire statique unique. Aucune chaîne d'outils Python ou Node.js, aucun conflit de dépendances. Le même binaire s'exécute sur votre ordinateur portable, en services distribués ou dans un cluster multinœud.",
 "c1.more": "Voir l'architecture →",
 "c2.h": "Une boucle d'agent déterministe et récupérable",
 "c2.p": "La boucle <code>forme</code> modélise chaque étape comme des actions et des observations explicites, avec points de reprise et reprise intégrés au moteur. Les exécutions d'agents se rejouent et s'auditent : finies les chaînes opaques qui disparaissent au moindre crash.",
 "c2.more": "Au cœur de la boucle →",
 "c3.h": "Orchestration multi-modèles adaptative",
 "c3.p": "Lancez un essaim de modèles qui débattent et révisent, faites passer la synthèse par un jury de vérification, et laissez le coordinateur <code>trinity</code> apprendre vers quel modèle router chaque tour : une stratégie évoluée, pas un planning figé.",
 "c3.more": "Le fonctionnement de l'orchestration →",
 "c4.h": "Une mémoire qui apprend, un contexte qui tient",
 "c4.p": "Le plan mémoire <code>plate</code> extrait des faits, les consolide pendant des phases de « rêve » en arrière-plan et propose un rappel hybride. La compaction du contexte et une montée en gamme des modèles maintiennent les longues exécutions dans la fenêtre.",
 "c4.more": "Mémoire &amp; données →",
 "c5.h": "Une gouvernance native, pas rajoutée après coup",
 "c5.p": "Multi-tenancy, clés API à portée limitée, RBAC, chaîne de filtres de politique dynamique avec validations humaines, audit structuré et masquage des données personnelles et secrets : tout au cœur du produit, avec un coffre-fort pour les identifiants et le câblage OAuth des fournisseurs.",
 "c5.more": "Entreprise &amp; sécurité →",
 "c6.h": "Des protocoles ouverts, sans verrouillage",
 "c6.p": "Expose une API compatible OpenAI et parle MCP (serveur et client), ACP et A2A pour la collaboration entre agents. Compatible avec les backends OpenAI, Anthropic, Ollama et GLM/Z.AI.",
 "c6.more": "Protocoles &amp; interfaces →",
 "exp.tag": "Explorer la plateforme",
 "exp.h2": "Sept plans, une presse",
 "exp.p": "Chaque plan gère une seule préoccupation derrière une frontière stricte. Suivez celui qui vous intéresse jusque dans le détail.",
 "exp.arch.h": "Architecture",
 "exp.arch.p": "Un atelier d'imprimerie de modules combinables, des configurations de déploiement du processus unique à la grille, un stockage adossé à galley et les binaires qui font tourner le tout.",
 "exp.more": "En savoir plus →",
 "exp.loop.h": "Boucle d'agent",
 "exp.loop.p": "La boucle <code>forme</code> déterministe — points de reprise et reprise, hooks Lua, synthèse vérifier-réviser, exécutions pilotées par objectif, et un harnais qui s'améliore tout seul.",
 "exp.more2": "En savoir plus →",
 "exp.tools.h": "Outils",
 "exp.tools.p": "Un large catalogue intégré — fichiers, shell, navigateur extracteur de DOM, SQL, ontologie — exécuté dans un bac à sable, via MCP ou sur des nœuds distants, plus des fonctions Lua/Python comme outils.",
 "exp.more7": "En savoir plus →",
 "exp.orch.h": "Orchestration",
 "exp.orch.p": "Essaims multi-modèles, le coordinateur évolué <code>trinity</code>, la délégation à des sous-agents et la fédération A2A entre pairs.",
 "exp.more3": "En savoir plus →",
 "exp.mem.h": "Mémoire &amp; données",
 "exp.mem.p": "Une mémoire cognitive avec phases de rêve, un rappel hybride, un graphe de connaissances, des requêtes SPARQL sur ontologie et des backends SQLite/PostgreSQL/MySQL.",
 "exp.more4": "En savoir plus →",
 "exp.onto.h": "Moteur d'ontologie",
 "exp.onto.p": "Un moteur natif qui construit des graphes de connaissances à partir d'un corpus et les sert via SPARQL en mémoire — une ontologie posée sur vos données, sans aucun triple store externe.",
 "exp.more6": "En savoir plus →",
 "exp.ent.h": "Entreprise &amp; sécurité",
 "exp.ent.p": "Multi-tenancy, RBAC et plan de politique, coffre-fort et OAuth, traçage OpenTelemetry, quotas d'usage, masquage, défense contre l'injection et robustesse.",
 "exp.more5": "En savoir plus →",
 "st.1": "binaire Go statique",
 "st.3": "surfaces de protocole ouvertes",
 "st.4": "le port par défaut, et l'année",
 "proto.tag": "Interopérabilité",
 "proto.h2": "Parle tous les protocoles qui comptent",
 "proto.openai": "<span class=\"mono\">/v1/chat/completions</span>, modèles, embeddings, runs et sessions prêts à l'emploi — pointez vos clients existants vers Jikji.",
 "proto.mcp": "Serveur et client Model Context Protocol via stdio — consommez des outils MCP ou exposez Jikji comme tel.",
 "proto.acp": "Agent Communication Protocol via stdio pour des pairs agents locaux basés sur des processus.",
 "proto.a2a": "Collaboration entre agents — répartition des tâches, délégation et collecte des résultats d'un agent à l'autre.",
 "ops.h": "Outils d'exploitation",
 "ops.p": "<span class=\"mono\">jikjictl</span> couvre les identifiants et le coffre-fort, le RBAC, la politique, les requêtes d'audit, le traçage, l'usage et une place de marché — auxquels s'ajoute un tableau de bord web qui ne stocke jamais de clés côté serveur.",
 "term.h": "Pensé pour le terminal",
 "term.p": "Chat TUI interactif, mode prompt unique, flux d'événements JSONL pour l'automatisation et un mode JSON-RPC façon MCP — des agents que vous pouvez chaîner par pipe.",
 "test.h": "Testé comme une infrastructure",
 "test.p": "Une porte <span class=\"mono\">make verify</span> déterministe, complétée par des tests de fumée en conditions réelles, encadrés, contre de vrais fournisseurs. Tests de performance, de fuzzing, de propriétés et de concurrence partout dans le code.",
 "nav.start": "Commencer",
 "start.h2": "Opérationnel en moins d'une minute",
 "cm1": "lancer le serveur (port par défaut 1377 — oui, ce 1377)",
 "cm2": "vérifier votre environnement local",
 "cm3": "ouvrir le chat TUI interactif",
 "cm4": "ou appeler l'API compatible OpenAI",
 "foot.tagline": "Les caractères mobiles à l'ère des agents.",
 "foot.author": "Conçu par Jioh L. Jung.",
 "foot.explore": "Explorer",
 "foot.project": "Projet",
 "nav.about": "À propos &amp; Contact",
 "crumb.home": "Accueil",
 "arch.kicker": "Architecture",
 "arch.title": "Un atelier d'imprimerie de <span class=\"accent\">modules combinables</span>",
 "arch.sub": "Chaque module gère une seule préoccupation derrière une frontière stricte, utilisable d'abord en intra-processus et conçu pour passer derrière HTTP ou gRPC sans réécrire la logique métier. Ensemble, ils composent une plateforme d'agents complète.",
 "arch.mods.tag": "Les modules",
 "arch.mods.p": "Les noms des modules suivent l'univers de l'imprimerie de Jikji : chacun prépare, autorise, compose, imprime ou diffuse la connaissance.",
 "g.forme": "forme verrouillée",
 "m.forme": "Boucle d'agent déterministe — délégation, intervention humaine, hooks Lua, points de reprise, événements d'étape.",
 "g.trinity": "trois juges",
 "m.trinity": "Coordinateur multi-modèles adaptatif — débat d'essaim, vérifier-réviser, routage évolué.",
 "g.compositor": "metteur en page",
 "m.compositor": "Orchestration des sessions, files d'attente, composition des flux et mémoire de collaboration.",
 "g.dispatch": "aiguillage du travail",
 "m.dispatch": "Ordonnancement par tenant/fournisseur/modèle, files bornées, nouvelles tentatives avec délai progressif, disjoncteurs.",
 "g.type": "caractères de plomb",
 "m.type": "Fournisseurs d'inférence sur backends compatibles OpenAI/Anthropic/Ollama/GLM, OAuth, sensible à la fenêtre de contexte.",
 "g.sorts": "pièces de caractère",
 "m.sorts": "Exécution d'outils, intégration MCP, runners, bac à sable et nœuds d'outils distants.",
 "g.press": "presse à imprimer",
 "m.press": "Entrée HTTP — API compatible OpenAI, streaming SSE, webhooks signés, idempotence.",
 "g.plate": "cliché stéréotype",
 "m.plate": "Mémoire cognitive — extraction de faits, phases de rêve, rappel hybride, compaction.",
 "g.lexicon": "lexique",
 "m.lexicon": "Graphe de connaissances et ontologie — SPARQL, reclassement sémantique, détection de contradictions.",
 "g.galley": "galée",
 "m.galley": "Enregistrements et liens partagés SQLite/PostgreSQL/MySQL pour la collaboration et un état durable.",
 "g.imprimatur": "autorisation d'imprimer",
 "m.imprimatur": "Multi-tenancy, authentification par clé API, portées/RBAC, entrée des identifiants, coffre-fort et OAuth.",
 "g.rubric": "feuille de style",
 "m.rubric": "Plan de décision d'autorisation — autoriser/refuser/demander, évaluation de politique, audit.",
 "g.proof": "épreuve",
 "m.proof": "Détection des données personnelles et des secrets, masquage réversible, normalisation de texte sûre pour l'audit.",
 "g.bookstore": "la librairie",
 "m.bookstore": "Place de marché de paquets et d'agents — manifestes, signature, installation, réconciliation.",
 "g.almanac": "almanach",
 "m.almanac": "Ordonnancement déterministe — cron, intervalles, lots et travaux de maintenance.",
 "g.foundry": "fonderie de caractères",
 "m.foundry": "Amorçage, configuration, diagnostics et pilotage de l'orchestration.",
 "arch.mods.note": "Quelques modules supplémentaires complètent la plateforme — <span class=\"mono\">screen</span> (la chaîne de filtres de politique dynamique), <span class=\"mono\">relay</span> (tunnels TLS vers les nœuds d'outils distants), <span class=\"mono\">usagelimit</span> et <span class=\"mono\">observability</span> — détaillés sur la page Entreprise.",
 "arch.prov.tag": "type — Fournisseurs &amp; Modèles",
 "arch.prov.h2": "Branchez n'importe quel modèle, routez-le à votre façon",
 "arch.prov.p": "La colonne vertébrale <span class=\"mono\">type</span> dialogue avec de nombreuses familles de fournisseurs derrière une interface unique : vous mélangez librement les modèles et basculez de l'un à l'autre sans toucher à vos agents.",
 "arch.prov.1.h": "De nombreuses familles de fournisseurs",
 "arch.prov.1.p": "Compatible OpenAI, Anthropic Messages, Ollama Cloud, GLM / Z.AI, xAI Grok et OpenAI Codex — sans oublier un fournisseur echo intégré pour le travail hors ligne. Catégories Chat, embedding et rerank, et tout endpoint compatible OpenAI vers lequel vous le pointez.",
 "arch.prov.2.h": "OAuth ou clés, à vous de choisir",
 "arch.prov.2.p": "Les identifiants proviennent de variables d'environnement, du vault ou d'une connexion par appareil OAuth (Codex, Grok) avec rafraîchissement automatique des jetons. Une clé de type <code>oauth:grok</code> est résolue au moment de la requête, et les clés en clair sont masquées lors de l'export de la configuration.",
 "arch.prov.3.h": "Routage intelligent",
 "arch.prov.3.p": "Alias de modèles, groupes de modèles avec stratégies <code>round_robin</code> / <code>first_available</code> / <code>failover</code>, rotation multi-clés et routage persistant tenant compte du cache — le routage relève de la configuration, pas du code.",
 "arch.prov.4.h": "Runtime conscient du fournisseur",
 "arch.prov.4.p": "La prise en compte de la fenêtre de contexte propre à chaque fournisseur alimente l'échelle de promotion des modèles, le cache de prompt natif du fournisseur est utilisé là où il est disponible, et les limites d'usage externes sont suivies par fournisseur.",
 "arch.prov.cap": "Mélangez les fournisseurs et donnez-leur des alias — OAuth, clés et votre propre endpoint côte à côte :",
 "arch.dep.tag": "Formes de déploiement",
 "arch.dep.h2": "Indépendant de l'échelle — du portable au centre de données, du local au distant, d'un à plusieurs",
 "arch.dep.p": "Le même binaire change de forme par simple configuration — à travers l'échelle, l'emplacement et le nombre d'instances. Lancez tout dans un seul processus, séparez les plans en services, déportez l'exécution des outils vers des nœuds distants, puis faites tourner de nombreuses instances derrière une base de données partagée — le tout sans rien changer à vos agents.",
 "arch.dep.1.h": "Un processus, priorité au local",
 "arch.dep.1.p": "Un binaire unique avec SQLite embarqué pour un état durable. Aucun service externe requis — toute la plateforme démarre à partir d'un seul fichier de configuration, sur un portable ou un boîtier en périphérie.",
 "arch.dep.2.h": "Scindé en services",
 "arch.dep.2.p": "Exécutez l'entrée <code>press</code>, le contrôleur <code>dispatch</code> et les nœuds d'outils dans des processus distincts. gRPC relie le contrôleur aux nœuds d'outils distants (avec TLS en option), tandis que le contrôleur dispatch coordonne les workers par l'intermédiaire de la base de données partagée. L'exécution des outils est confiée aux workers <code>jikji-tool-node</code> derrière un tunnel <code>jikji-relay</code>.",
 "arch.dep.3.h": "Cluster multi-nœuds",
 "arch.dep.3.p": "Pointez <code>galley</code> vers un PostgreSQL ou un MySQL partagé pour assurer la haute disponibilité multi-nœuds, coordonnez dispatch par l'intermédiaire de la base de données partagée avec des baux distribués, des disjoncteurs par nœud et un mécanisme de bascule, puis exportez les traces et les métriques vers votre stack.",
 "arch.dep.note": "<b>Profils</b> — des préréglages d'amorçage (<span class=\"mono\">desktop</span>, <span class=\"mono\">edge</span>, <span class=\"mono\">controller</span>, <span class=\"mono\">all</span>) déterminent quels plans un nœud fait tourner, si bien que la même image remplit n'importe quel rôle dans le cluster.",
 "arch.dep.cap": "La haute disponibilité multi-nœuds est une affaire de configuration, pas de réécriture — pointez le même binaire vers une base partagée :",
 "arch.dep.free.h": "Libre sur chaque axe.",
 "arch.dep.free.scale.l": "Sans limite d'échelle",
 "arch.dep.free.scale.d": "de l'ordinateur portable au centre de données.",
 "arch.dep.free.loc.l": "Sans contrainte de lieu",
 "arch.dep.free.loc.d": "de l'exécution locale jusqu'aux nœuds distants.",
 "arch.dep.free.net.l": "Sans barrière réseau",
 "arch.dep.free.net.d": "un tunnel relais TLS atteint les nœuds à travers les réseaux, derrière un NAT ou un pare-feu, sur site ou dans n'importe quel cloud — ainsi des environnements qui ne pouvaient pas se voir rejoignent un même maillage.",
 "arch.dep.free.os.l": "Sans frontière de région &amp; d'OS",
 "arch.dep.free.os.d": "les outils s'exécutent là où vit le nœud, sous Linux, macOS ou Windows.",
 "arch.dep.free.inst.l": "Sans contrainte d'instance",
 "arch.dep.free.inst.d": "un seul processus ou plusieurs derrière une base de données partagée, avec élection de leader en HA.",
 "arch.dep.free.foot": "Même binaire, mêmes agents ; seule la configuration change.",
 "arch.store.tag": "Stockage &amp; binaires",
 "arch.store.h2": "Un état centré sur galley, cinq binaires",
 "arch.store.p": "<b>galley</b> est l'espace de travail collaboratif partagé — un schéma unique, avec des migrations explicites, qui sous-tend la mémoire, les enregistrements de dispatch, la place de marché, les tâches A2A, les identifiants et les journaux d'audit. Il tourne par défaut sur SQLite embarqué, et sur PostgreSQL ou MySQL pour les déploiements multi-nœuds, avec un DDL adapté au dialecte et un gestionnaire de baux distribué pour la reprise des tâches.",
 "arch.bin.1.k": "jikji",
 "arch.bin.1.v": "Le serveur runtime principal — boucle d'agent, API compatible OpenAI, dispatch, canaux et tableau de bord, selon le profil choisi.",
 "arch.bin.2.k": "jikjictl",
 "arch.bin.2.v": "La CLI d'exploitation — santé, modèles, identifiants et coffre-fort, RBAC, politique, filtres, OAuth des fournisseurs, usage, audit et place de marché.",
 "arch.bin.3.k": "jikjicode",
 "arch.bin.3.v": "Une CLI de codage autonome qui pilote des outils locaux en bac à sable face à un serveur de modèles distant compatible OpenAI.",
 "arch.bin.4.k": "jikji-relay",
 "arch.bin.4.v": "Un proxy de tunnel TLS (TLS 1.3) qui relie un contrôleur à des nœuds d'outils distants à travers les réseaux.",
 "arch.bin.5.k": "jikji-tool-node",
 "arch.bin.5.v": "Un exécuteur d'outils distant — il s'enregistre auprès du contrôleur, exécute les outils dans le bac à sable et signale sa santé par battements de cœur.",
 "arch.proto.h2": "Des interfaces aux protocoles ouverts",
 "arch.proto.p": "Jikji est conçu pour s'insérer dans ce que vous faites déjà tourner — pointez-y vos clients OpenAI existants, faites le pont MCP dans les deux sens ou fédérez vos agents en A2A.",
 "arch.proto.openai": "<span class=\"mono\">/v1/chat/completions</span>, <span class=\"mono\">/v1/models</span>, <span class=\"mono\">/v1/embeddings</span>, plus des runs et sessions d'agents natifs.",
 "arch.proto.mcp": "Serveur et client Model Context Protocol via stdio — consommez des outils MCP ou exposez Jikji comme tel.",
 "arch.proto.acp": "Agent Communication Protocol via stdio pour des pairs agents locaux basés sur des processus.",
 "arch.proto.a2a": "Répartition et registre des tâches entre agents via gRPC, ainsi qu'un canal gRPC vers les nœuds d'outils distants. Le travail multi-nœuds est coordonné au moyen de la base de données galley partagée et de baux distribués.",
 "arch.routes.1.k": "Chat &amp; modèles",
 "arch.routes.2.k": "Runs d'agents",
 "arch.routes.3.k": "Santé &amp; exploitation",
 "arch.routes.4.k": "Administration",
 "arch.routes.4.note": "(réservé aux opérateurs)",
 "arch.perf.tag": "Performance &amp; efficacité",
 "arch.perf.h2": "Beaucoup de sessions, une empreinte minime",
 "arch.perf.p": "Un cœur Go compilé, et non un interpréteur : il ne paie donc jamais la lourde facture de mémoire et de latence que traînent les stacks fondées sur des scripts (Python ou Node.js). Un seul nœud sert de nombreuses sessions simultanées tout en restant léger en mémoire et prompt à répondre. L'efficacité ne dépend pas de l'échelle : le même runtime consomme à peine sur un ordinateur portable et abat davantage de travail par cœur sur un serveur.",
 "arch.perf.1.h": "De la concurrence sans le poids",
 "arch.perf.1.p": "Les goroutines Go gèrent des dizaines de sessions simultanées dans un seul processus — souvent pour une fraction de pourcent d'un seul cœur CPU — sans aucun interpréteur ni runtime à lancer par session. Le travail s'exécute d'abord en interne, si bien que la coordination est un appel de fonction, pas un saut réseau.",
 "arch.perf.2.h": "Rapide par conception",
 "arch.perf.2.p": "Un routage collant attentif au cache, la mise en cache native des prompts côté fournisseur et un cache de réponses sémantique réduisent les appels de modèle redondants ; disjoncteurs et files d'attente bornées empêchent qu'un amont lent ne ralentisse tout le reste.",
 "arch.perf.3.h": "Empreinte minimale",
 "arch.perf.3.p": "Un binaire statique avec SQLite intégré et mise en cache de mémo sur le chemin chaud maintient l'empreinte résidente autour de 50&nbsp;MB sans le moteur d'ontologie chargé — mémoire et CPU minimales par session, d'un ordinateur portable à un nœud multi-locataire dense.",
 "arch.perf.note": "<b>Une efficacité indépendante de l'échelle.</b> Sur un ordinateur portable, il reste frais et consomme très peu, laissant la batterie et les ventilateurs tranquilles. Sur un serveur, ce même binaire répond plus vite et accueille davantage de sessions simultanées par cœur — moins de matériel pour la même charge. Un seul runtime, ajusté par l'endroit où il tourne.",
 "pn.back": "← Retour",
 "pn.home": "Vue d'ensemble",
 "pn.next": "Suivant →",
 "loop.kicker": "Le harnais",
 "loop.title": "Une boucle d'agent déterministe et <span class=\"accent\">récupérable</span>",
 "loop.sub": "Le harnais <span class=\"mono\">forme</span> modélise chaque étape comme une action et une observation explicites. Les exécutions enregistrent un point de reprise après chaque étape, redémarrent exactement là où elles s'étaient arrêtées et ne perdent jamais de travail en silence — une boucle d'agent se comporte ainsi comme une transaction, pas comme une boîte noire.",
 "loop.l.tag": "La boucle",
 "loop.l.h2": "Planifier → agir → observer → intégrer, et recommencer",
 "loop.l.p": "Un planificateur propose l'action suivante ; le moteur la valide, l'exécute, intègre l'observation dans l'état et émet un événement d'étape. Chaque type d'action est explicite et borné.",
 "loop.dia.1": "proposer l'action suivante",
 "loop.dia.2": "valider &amp; exécuter",
 "loop.dia.3": "intégrer une observation typée",
 "loop.dia.4": "persister &amp; émettre un événement d'étape",
 "loop.dia.back": "↻ recommencer jusqu'à <span class=\"mono\">respond</span>, <span class=\"mono\">stop</span> ou l'épuisement du budget d'étapes",
 "loop.act.label": "Types d'action<span class=\"mono\">forme.Action</span>",
 "loop.act.p": "Chaque tour aboutit à exactement une action, validée avant son exécution :",
 "loop.act.1": "<code>think</code> — consigner un raisonnement sans effet externe.",
 "loop.act.2": "<code>tool</code> — appeler un outil, en ligne pour un seul ou en file pour une exécution en parallèle.",
 "loop.act.3": "<code>respond</code> / <code>stop</code> — émettre la réponse finale et terminer l'exécution.",
 "loop.act.4": "<code>delegate</code> — confier une sous-tâche à un agent enfant et en récupérer le résultat.",
 "loop.act.5": "<code>wait</code> — mettre l'exécution en pause jusqu'à un événement externe ou un délai d'expiration.",
 "loop.act.note": "Le budget d'étapes par tour suit le plafond déclaré par le modèle choisi (1024 par défaut en local, garde-fou absolu à 4096 ; plafond distant à 1024), afin que chaque boucle se termine sans imposer le même horizon fixe à tous les modèles.",
 "loop.obs.label": "Observations<span class=\"mono\">categorized</span>",
 "loop.obs.p": "Les résultats sont réintégrés sous forme d'observations typées, pour une trace lisible par machine plutôt qu'en texte libre :",
 "loop.obs.1": "observations de pensée, de résultat d'outil et d'erreur",
 "loop.obs.2": "observations de politique lorsqu'une porte autorise, refuse ou demande",
 "loop.obs.3": "observations d'attente lorsque l'exécution se met en pause",
 "loop.obs.4": "observations de collecte lorsque le résultat d'un sous-agent est réintégré par synthèse",
 "loop.ckpt.label": "Point de reprise &amp; reprise<span class=\"mono\">exactly-once</span>",
 "loop.ckpt.p": "Un point de reprise est persisté après chaque étape — tenant, indice d'étape, identifiant du dernier appel d'outil et état d'attente éventuel. À la reprise, les étapes terminées sont restaurées dans la trace et <b>les outils ne sont jamais réexécutés</b> (dédoublonnage par identifiant d'appel) ; la boucle reprend à l'étape suivante.",
 "loop.ckpt.1": "se mettre en pause sur <code>wait</code>, puis se réveiller à la fin d'un enfant ou sur un délai d'expiration",
 "loop.ckpt.2": "résistant aux crashs : une exécution survit aux redémarrages de processus et reprend là où elle s'était arrêtée",
 "loop.ckpt.3": "rejouable et auditable de bout en bout",
 "loop.lua.label": "Hooks Lua &amp; questionnaires<span class=\"mono\">scripts de confiance</span>",
 "loop.lua.p": "Des hooks Lua de confiance injectent des plans et des consignes dans la boucle, avec des liaisons pour les questionnaires, le débat, le coût, le budget et le lexicon. Le système de questionnaires recueille des réponses structurées via des formulaires durables, qui se mettent en pause puis reprennent — l'exécution se bloque sur une question et continue une fois la réponse fournie.",
 "loop.verify.label": "Synthèse vérifier-réviser<span class=\"mono\">gated</span>",
 "loop.verify.p": "Une réponse finale peut être soumise à un jury de vérification : si la majorité vote RÉVISER, la boucle resynthétise en tenant compte de la critique, dans la limite d'un nombre de tours borné. On peut empêcher la sortie brute d'un outil de court-circuiter la réponse, pour que les modèles raisonnent sur les résultats au lieu de renvoyer des données non traitées.",
 "loop.ctx.label": "Contexte &amp; budget<span class=\"mono\">reste dans la fenêtre</span>",
 "loop.ctx.p": "Une montée en gamme des modèles réessaie un tour qui déborde sur la fenêtre de contexte supérieure et y reste promu. Des indices dynamiques par tour transmettent des consignes vers l'avant, et un budget d'exécution (jetons max, temps réel max) s'arrête proprement — en produisant une réponse finale synthétisée plutôt qu'une coupure nette.",
 "loop.goal.label": "Exécutions pilotées par objectif<span class=\"mono\">set · evaluate · report</span>",
 "loop.goal.p": "Au-delà d'un simple prompt, une exécution peut poursuivre un <b>objectif</b> durable. Une boucle pilotée par objectif fait avancer le travail d'une itération à l'autre — chacune s'appuyant sur tout ce qui a déjà été produit — et s'arrête quand le modèle signale que l'objectif est atteint ou qu'une limite est franchie.",
 "loop.goal.1": "définir un objectif, l'enrichir et le concrétiser en travail réel",
 "loop.goal.2": "évaluer l'avancement et rendre compte de l'état par rapport à l'objectif",
 "loop.goal.3": "persistant d'une session à l'autre — un objectif survit à n'importe quelle exécution",
 "loop.human.label": "Humain dans &amp; sur la boucle<span class=\"mono\">approuver · superviser</span>",
 "loop.human.in": "<b>Humain dans la boucle (« human in the loop »).</b> Les points de validation et les requêtes mettent l'exécution en pause pour une décision — l'agent se bloque jusqu'à ce qu'une personne approuve, refuse ou réponde, puis reprend exactement au point de contrôle où il s'était arrêté. Rien de risqué ne se produit à votre insu.",
 "loop.human.on": "<b>Humain sur la boucle (« human on the loop »).</b> Par défaut, une exécution diffuse chaque étape en temps réel : un opérateur observe en direct et n'intervient qu'en cas de besoin — basculer la politique d'un outil sur <code>ask</code>, répondre à une requête, annuler une exécution ou restaurer une session à un instantané sain. Une supervision sans avoir à tout surveiller de près.",
 "loop.cfg.cap": "Façonnez la boucle avec un planificateur, des profils nommés et des hooks Lua :",
 "loop.trace.cap": "Chaque étape est émise comme un événement JSONL — rejouable et auditable :",
 "loop.self.tag": "Auto-amélioration &amp; extensibilité",
 "loop.self.h2": "Une boucle qui réécrit son propre manuel",
 "loop.self.p": "Le harnais n'est pas figé à la compilation. Il apprend des procédures réutilisables, se remodèle via Lua, recherche ce qu'il ignore et adopte de nouveaux outils — le tout sans jamais forker le moteur.",
 "loop.self.1.h": "Il apprend des compétences réutilisables",
 "loop.self.1.p": "Après une exécution conséquente, un réviseur post-exécution borné distille ce que l'agent a découvert en une <b>compétence</b> durable — pour que la prochaine exécution démarre avec une longueur d'avance. Les compétences se chargent à la demande via <code>skill.load</code> et s'attachent à un profil ou correspondent à l'objectif par mot-clé.",
 "loop.self.2.h": "Remodeler la boucle avec Lua",
 "loop.self.2.p": "Des hooks Lua de confiance placés sur <code>plan</code>, <code>before_tool</code> et <code>after_tool</code> vous permettent — à vous comme à l'agent lui-même — de modifier à l'exécution la façon dont la boucle planifie et appelle les outils, le tout dans un budget strict de temps et d'instructions.",
 "loop.self.3.h": "Une recherche aux affirmations vérifiées",
 "loop.self.3.p": "Le mécanisme de recherche planifie une investigation, rassemble des sources et lance une recherche web — et soumet ses propres conclusions à une exigence scientifique : la prédiction est <b>préenregistrée</b> avant toute preuve, le protocole expérimental est gelé, et l'affirmation n'est confirmée qu'à partir d'exécutions réelles, répétées et analysées par la machine. Des métriques de qualité mécaniques (aucun LLM ne se juge lui-même) pilotent ensuite une boucle de révision bornée. Le même mécanisme soutient les portes de déploiement et les garde-fous anti-régression, pas seulement des publications.",
 "loop.self.4.h": "Extensible par conception",
 "loop.self.4.p": "Les compétences, les hooks Lua, les outils MCP et les installations signées depuis la marketplace étendent tous la même boucle. Toute nouvelle capacité s'ajoute autour du moteur, jamais en le réécrivant.",
 "loop.lh.tag": "Le long horizon",
 "loop.lh.h2": "Prêt pour le travail agentique à long horizon",
 "loop.lh.p": "Les vrais workflows agentiques ne se terminent pas d'un seul souffle — ils s'exécutent pendant des heures, attendent le monde extérieur et s'étalent sur des jours. Chaque primitive de cette page existe pour qu'une exécution puisse aller au bout sans perdre le fil.",
 "loop.lh.1.h": "Un état qui survit à tout",
 "loop.lh.1.p": "Les points de contrôle, étape par étape, sont enregistrés dans un stockage durable : une exécution survit ainsi aux redémarrages de processus, aux plantages et aux redéploiements — et reprend exactement là où elle s'était arrêtée, sans réexécuter le moindre outil.",
 "loop.lh.2.h": "Mettez en pause, reprenez plus tard",
 "loop.lh.2.p": "Une exécution peut attendre un événement externe, une approbation ou un agent enfant, puis se réveiller des heures ou des jours plus tard — rien n'a besoin de rester épinglé en mémoire pendant toute la durée.",
 "loop.lh.3.h": "Des objectifs qui survivent à une exécution",
 "loop.lh.3.p": "Un objectif durable est porté à travers de nombreuses exécutions et sessions jusqu'à ce qu'il soit atteint — un travail au long cours garde la mémoire de sa propre intention, et pas seulement de son dernier tour.",
 "loop.lh.4.h": "Cohérent sur toute la distance",
 "loop.lh.4.p": "La compaction du contexte et l'échelle de promotion des modèles maintiennent les exécutions très longues dans la fenêtre, et le planificateur <code>almanac</code> pilote les tâches récurrentes — un workflow peut donc s'étaler sur des jours tout en gardant le fil.",
 "loop.lh.5.h": "Chaque tour passe par un filtre",
 "loop.lh.5.p": "Avant qu'un tour planifié ou autonome ne consomme la moindre puissance de calcul, la boucle le classe — <code>deliver</code>, <code>ask</code> à un humain, <code>wait</code> une preuve, <code>self-repair</code>, ou rester <code>quiet</code> — au travers d'une pile de filtres à priorité fixe, de sorte qu'un blocage de santé ou une approbation en attente prime toujours sur le budget restant. Aucune exécution ne brûle des tokens simplement parce qu'elle le peut.",
 "loop.lh.6.h": "Des objectifs avec une ligne d'arrivée",
 "loop.lh.6.p": "Les objectifs sont structurés et hiérarchiques — les sous-objectifs remontent vers leur parent — et portent des KPI derrière une porte d'acceptation mécanique avec traçabilité des preuves. Une exécution longue est jugée terminée sur des preuves mesurables, et non sur la parole du modèle.",
 "orch.kicker": "Plusieurs modèles, une seule press",
 "orch.title": "Faire jouer <span class=\"accent\">plusieurs modèles</span> de concert",
 "orch.sub": "Un modèle est un seul sort ; l'orchestration est la page composée. Jikji fait tourner des essaims qui débattent et révisent, un coordinateur évolué qui apprend vers quel modèle router chaque tour, et une délégation qui répartit le travail entre sous-agents et pairs.",
 "orch.sw.tag": "Multi-modèles",
 "orch.sw.h2": "Des essaims qui débattent, puis une synthèse filtrée",
 "orch.sw.p": "Plusieurs modèles répondent à la même question, se critiquent mutuellement tour après tour, et un synthétiseur rédige la réponse finale — vérifiée au besoin avant publication.",
 "orch.sw.1.h": "Débattre &amp; synthétiser",
 "orch.sw.1.p": "Chaque participant propose d'abord une réponse, puis on enchaîne des tours bornés de critique et de révision. Un synthétiseur compose le résultat ; vérification activée, un jury tranche entre ACCEPTER et RÉVISER, et resynthétise dès qu'une majorité vote RÉVISER.",
 "orch.sw.2.h": "Itérer vers un seuil de qualité",
 "orch.sw.2.p": "Faites passer un seul modèle par des tours répétés d'amélioration et de contrôle jusqu'à atteindre un seuil de qualité ou une limite d'étapes — utile pour rédiger, refactoriser et s'auto-corriger.",
 "orch.sw.3.h": "Comparer des candidats",
 "orch.sw.3.p": "Lancez la même tâche sur plusieurs modèles ou réglages et comparez les candidats côte à côte, pour que le routage et le choix des fournisseurs reposent sur des preuves, pas sur des suppositions.",
 "orch.sw.cap": "Appelez un essaim comme un outil — les participants débattent, puis un jury de vérification filtre le résultat :",
 "orch.tr.tag": "trinity — le coordinateur",
 "orch.tr.h2": "Un coordinateur qui apprend le routage",
 "orch.tr.p": "La plupart des systèmes « multi-agents » suivent un script figé. Le coordinateur <span class=\"mono\">trinity</span> applique une politique apprise à l'état réel d'une exécution — quel modèle, dans quel rôle, à ce tour précis. C'est une politique que vous faites évoluer et que vous activez ; par défaut, l'ensemble s'appuie sur le panel divers sous contrôle de vérificateur.",
 "orch.tr.role.label": "Boucle à trois rôles<span class=\"mono\">thinker · worker · verifier</span>",
 "orch.tr.role.p": "Un pool hétérogène d'agents est mené à travers une boucle penseur / exécutant / vérificateur. À chaque tour, le coordinateur choisit quel agent agit et dans quel rôle, en retenant celui qui convient le mieux à l'état courant de la tâche.",
 "orch.tr.route.label": "Routage adaptatif<span class=\"mono\">politique évoluée</span>",
 "orch.tr.route.p": "La politique de sélection est construite sur des caractéristiques observables — indice du tour, existence ou non d'un plan, dernier verdict, nombre de révisions et signaux de la tâche — et entraînée par une stratégie d'évolution CMA-ES séparable, puis enregistrée et servie lorsque vous l'activez. Il en résulte un routage adaptatif, pas un planning codé en dur.",
 "orch.tr.ens.label": "Ensemble &amp; vérifier-réviser<span class=\"mono\">porte de qualité</span>",
 "orch.tr.ens.p": "La coordination se combine à la porte vérifier-réviser de la boucle et à la synthèse d'ensemble : plusieurs modèles contribuent et un vérificateur tient le seuil avant qu'une réponse ne soit renvoyée.",
 "orch.tr.oracle.label": "Contrôle de dérive<span class=\"mono\">oracle</span>",
 "orch.tr.oracle.p": "Un outil <code>trinity.oracle</code> exécute un contrôle de cohérence de dérive — il audite si une exécution est restée cohérente avec son objectif, son plan et ses preuves. C'est un auto-audit que n'importe quel agent peut invoquer pour détecter une exécution qui a discrètement dévié de sa tâche.",
 "orch.tr.cap": "Les stratégies de routage se configurent par groupe de modèles :",
 "orch.del.tag": "Délégation &amp; fédération",
 "orch.del.h2": "Des sous-agents aux pairs à travers le réseau",
 "orch.del.1.h": "Déléguer à des sous-agents",
 "orch.del.1.p": "Une action <code>delegate</code> confie une sous-tâche délimitée à un agent enfant. Les créations sont idempotentes — indexées par <code>(parent, request_key)</code> pour qu'une nouvelle tentative ne crée jamais de doublon — et portent un rôle limité à la tâche. Un superviseur suit les enfants, récupère leurs résultats dans la trace du parent, et une carte de score audite les résultats.",
 "orch.del.2.h": "Fédération A2A",
 "orch.del.2.p": "Le protocole agent-à-agent couvre la création / envoi / récupération / annulation de tâches ainsi qu'un registre d'agents avec pulsation. Utilisez-le pour des pairs explicitement configurés et limités au locataire ; la fédération inter-locataire n'est pas présentée comme une frontière de sécurité prise en charge.",
 "orch.del.3.h": "Mémoire de collaboration",
 "orch.del.3.p": "L'espace de travail <code>galley</code> conserve les enregistrements partagés, les tâches déléguées et l'intention de conversation au fil des sessions, avec un gestionnaire de baux à TTL qui revendique les tâches et récupère celles laissées orphelines.",
 "orch.del.4.h": "Protocoles d'agents ouverts",
 "orch.del.4.p": "Au-delà d'A2A, Jikji parle MCP et ACP via stdio pour les pairs locaux, et coordonne le dispatch multi-nœuds en gRPC — pour que l'orchestration ne soit jamais liée à un seul runtime.",
 "orch.del.5.h": "Des plans sous forme de graphes de dépendances",
 "orch.del.5.p": "<code>taskgraph.run</code> exécute un plan entier : les tâches reliées par des arêtes <code>depends_on</code> s'exécutent chacune comme un sous-agent durable une fois leurs dépendances terminées. Les tâches d'une même vague s'exécutent en parallèle — sauf si elles touchent le même fichier, auquel cas elles sont sérialisées — et le graphe est validé en amont : un cycle est rejeté avant que quoi que ce soit ne démarre.",
 "orch.svc.tag": "Une session en tant que service",
 "orch.svc.h2": "Transformez une session en service — souvent sans code",
 "orch.svc.p": "Ce que vous construisez dans un chat, c'est le produit. jikji peut servir une session préparée comme un modèle, filtrer sa sortie avec Lua, exposer votre ontologie et l'exécuter selon un calendrier — un nouvel agent de service devient une simple configuration, et non une base de code.",
 "orch.svc.1.h": "Une session devient un modèle",
 "orch.svc.1.p": "Enregistrez une session préparée — son contexte capturé sous forme de préfixe prompt-cache — et elle apparaît dans <code>/v1/models</code>, immédiatement appelable comme un id de modèle. L'amorçage coûteux devient un hit de cache à chaque appel, le contexte est donc préservé à moindre coût. Aucun nouveau code, aucun redéploiement.",
 "orch.svc.2.h": "Filtrez les réponses avec Lua",
 "orch.svc.2.p": "Un filtre de contenu Lua à sécurité intégrée examine et remodèle ce qui passe — caviarder, réécrire ou bloquer une réponse avant qu'elle n'atteigne l'appelant — avec un HTTP optionnel et sur liste blanche pour l'enrichissement.",
 "orch.svc.3.h": "Exposez l'ontologie",
 "orch.svc.3.p": "Exposez le graphe de connaissances natif comme un service interrogeable, afin que SPARQL et la recherche sémantique soient accessibles à tous les appelants — pas seulement à l'agent qui l'a construit.",
 "orch.svc.4.h": "Exécutez-la selon un calendrier",
 "orch.svc.4.p": "Le planificateur <code>almanac</code> pilote les tâches cron et par intervalle — un rafraîchissement nocturne de l'ontologie, un rapport périodique, une vérification récurrente — sans aucun planificateur externe à raccorder.",
 "orch.svc.5.h": "Rejoignez vos utilisateurs sur leurs canaux",
 "orch.svc.5.p": "Proposez le même agent sur vos canaux de messagerie : un message entrant devient une exécution et la réponse repart aussitôt, avec des portées d'outils propres à chaque conversation, une mémoire persistante par conversation, des listes d'autorisation et des limites de débit. Un adaptateur Telegram est disponible dès aujourd'hui, et l'interface d'adaptateur est conçue pour aller plus loin — Slack et au-delà — le tout complété par des webhooks entrants signés.",
 "orch.svc.6.h": "Les agents publient leurs propres surfaces",
 "orch.svc.6.p": "Un agent peut publier une UI en direct avec <code>ui.render</code> — un tableau ou un graphique déclaratif est servi immédiatement (rendu côté serveur, aucun script d'agent ne s'exécute) — ou une API sur <code>/svc/{tenant}/{name}</code> avec <code>service.publish</code> : un corps statique, un handler Lua sandboxé, ou un modèle d'objectif où <b>chaque requête déclenche une exécution d'agent durable</b>. Tout ce qui exécute du code est publié en attente et n'est servi qu'après approbation d'un opérateur.",
 "orch.xr.tag": "Multi-régions &amp; multi-OS",
 "orch.xr.h2": "Des outils sans frontières",
 "orch.xr.p": "Un appel d'outil n'a pas à s'exécuter là où l'agent réfléchit. Les outils s'exécutent sur des nœuds distants choisis selon leur capacité et leur placement, joignables via des tunnels relais — une seule exécution peut ainsi s'étendre à travers machines, clouds, régions et systèmes d'exploitation, avec un catalogue partagé durable, des disjoncteurs par nœud et un basculement automatique.",
 "orch.xr.eg": "<b>Une exécution, trois régions, trois systèmes d'exploitation.</b> Lisez les journaux sur un nœud Linux à Seattle, mettez à l'échelle un conteneur depuis un nœud macOS à Tokyo, puis vérifiez la réponse depuis un nœud Windows à Séoul — chaque outil routé vers le nœud capable de l'exécuter, le tout au sein d'une seule exécution d'agent déterministe et à points de contrôle.",
 "mem.kicker": "plate · lexicon · galley",
 "mem.title": "Une mémoire qui <span class=\"accent\">apprend</span>, un contexte qui tient",
 "mem.sub": "Le plan mémoire <span class=\"mono\">plate</span> extrait des faits, les consolide au repos et propose un rappel hybride — pendant que la compaction du contexte et une montée en gamme maintiennent les longues exécutions dans la fenêtre. La connaissance vit dans un graphe que vous interrogez en SPARQL, sur la base de données que vous utilisez déjà.",
 "mem.cm.tag": "plate — mémoire cognitive",
 "mem.cm.h2": "Extraire, consolider, rappeler",
 "mem.cm.store.label": "Stockages en couches<span class=\"mono\">un seul plan</span>",
 "mem.cm.store.p": "La mémoire n'est pas un fourre-tout unique. Le plate conserve une mémoire de travail des tours récents, des embeddings vectoriels denses, des triplets sémantiques extraits, des entités résolues et une couche d'ontologie — interrogés ensemble.",
 "mem.cm.recall.label": "Rappel hybride<span class=\"mono\">BM25 + vecteurs</span>",
 "mem.cm.recall.p": "Le rappel combine recherche par mots-clés (BM25) et recherche sémantique vectorielle, partitionnées par tenant et par acteur, pour que la mémoire ne fuite jamais d'un sujet à l'autre. Un backend natif <code>sqlite-vec</code> est utilisé quand l'extension est disponible.",
 "mem.cm.dream.label": "Phases de rêve<span class=\"mono\">consolidation en arrière-plan</span>",
 "mem.cm.dream.p": "Des passes planifiées en arrière-plan consolident la mémoire de travail vers le stockage long terme — en notant les faits selon leur importance et leur fraîcheur, en détectant les contradictions entre sessions et en marquant comme obsolètes les faits dont les sources évoluent.",
 "mem.ctx.tag": "Optimisation du contexte &amp; des jetons",
 "mem.ctx.h2": "Faire tenir davantage dans chaque fenêtre",
 "mem.ctx.p": "Les longues exécutions d'agents font exploser les fenêtres de contexte et consomment des jetons. Jikji traite la fenêtre comme une ressource à gérer, pas comme un mur où s'écraser.",
 "mem.ctx.1.h": "Compaction du contexte",
 "mem.ctx.1.p": "Les tours anciens et peu importants sont évincés selon un score d'importance avant que la fenêtre ne déborde, afin que le fil conserve l'essentiel tout en maintenant le nombre de jetons dans une limite définie — la compaction se déclenche lorsqu'une exécution approche de sa limite.",
 "mem.ctx.2.h": "Montée en gamme des modèles",
 "mem.ctx.2.p": "Quand un tour risque de déborder, l'exécution réessaie sur la fenêtre de contexte supérieure et y reste promue — au lieu d'échouer ou de tronquer le prompt en silence.",
 "mem.ctx.3.h": "Cache de chemin critique &amp; de prompt",
 "mem.ctx.3.p": "Un mémo borné en intra-processus met en cache les recalculs fréquents, un cache cloisonné par tenant sert les résultats partagés entre requêtes, et le cache de prompt natif des fournisseurs (cache-control, clés de cache) est exploité là où il est disponible.",
 "mem.ctx.4.h": "Un chemin d'embedding distinct",
 "mem.ctx.4.p": "Le rappel et le reclassement s'exécutent sur leur propre chemin d'embedding — choisissez le modèle de votre choix (Jina, OpenAI ou Ollama), indépendant du fournisseur de chat afin que la recherche soit réglée séparément. C'est optionnel : sans fournisseur d'embedding configuré, le système fonctionne uniquement par graphe et mots-clés.",
 "mem.ctx.cap": "Le cache de réponses sémantique réutilise les réponses par le sens, pas par le texte exact :",
 "mem.kg.tag": "lexicon — connaissances &amp; ontologie",
 "mem.kg.h2": "Un graphe de connaissances que vous pouvez interroger",
 "mem.kg.build.label": "Construire à partir de documents<span class=\"mono\">lexicon</span>",
 "mem.kg.build.p": "Le lexicon extrait des documents les entités et les relations vers un graphe de connaissances, résout les contradictions par politique et reclasse les faits récupérés par similarité sémantique. Un moteur de guidage injecte des motifs FOLLOW déterministes ou apprend de nouvelles directives ADAPT.",
 "mem.kg.sparql.label": "SPARQL 1.1<span class=\"mono\">RDF natif</span>",
 "mem.kg.sparql.p": "Un magasin de triplets RDF embarqué avec analyse TTL répond aux requêtes SPARQL 1.1 SELECT — motifs de graphe de base, FILTER, OPTIONAL, UNION, MINUS, BIND, VALUES, chemins de propriété, sous-requêtes et agrégation avec GROUP BY et HAVING — le tout avec une protection sur la taille des résultats.",
 "mem.kg.rerank.label": "Reclassement sémantique<span class=\"mono\">pertinence</span>",
 "mem.kg.rerank.p": "Des ontologies chargées depuis le catalogue, un cloisonnement par tenant et un reclassement sémantique permettent à la récupération de s'appuyer sur un sens structuré plutôt que sur le seul recoupement de mots-clés.",
 "mem.kg.cap": "Interrogez le graphe de connaissances en SPARQL 1.1 :",
 "mem.okf.tag": "Échange de connaissances portable",
 "mem.okf.h2": "OKF en entrée ; lexicon et RDF en sortie",
 "mem.okf.p": "Jikji fait le pont entre l'Open Knowledge Format (markdown et frontmatter YAML) et son graphe lexicon natif ainsi que son pipeline RDF/TTL, tout en préservant un bundle portable que d'autres systèmes peuvent lire.",
 "mem.okf.1.h": "Aller-retour sans perte",
 "mem.okf.1.p": "Le pont intégré exporte et importe 66 concepts et 68 assertions sans perte d'identité ni de relation, puis valide 3,086 triplets RDF avec lint et SHACL.",
 "mem.okf.2.h": "Typé et auditable",
 "mem.okf.2.p": "Les liens OKF portables restent du markdown lisible ; Jikji ajoute des relations typées, un niveau de confiance, des citations de preuves, la provenance et des enregistrements de graphe interrogeables, sans enfermer la source dans un format propriétaire.",
 "mem.db.tag": "galley — stockage",
 "mem.db.h2": "La base de données que vous utilisez déjà",
 "mem.db.p": "Tout l'état durable — mémoire, runs, tâches, place de marché, identifiants, audit — vit dans un seul schéma explicite et migré, derrière l'espace de travail <span class=\"mono\">galley</span>.",
 "mem.db.1.k": "SQLite",
 "mem.db.1.v": "Le choix par défaut — embarqué, état durable sans configuration pour les déploiements bureautiques et mono-nœud, avec mode WAL et gestion des nouvelles tentatives sur base occupée.",
 "mem.db.2.k": "PostgreSQL",
 "mem.db.2.v": "Runtime à base partagée pour la haute disponibilité multi-nœuds, avec des migrations adaptées au dialecte et un gestionnaire de baux distribué pour la reprise des tâches.",
 "mem.db.3.k": "MySQL",
 "mem.db.3.v": "Une seconde option de base partagée pour la HA multi-nœuds, derrière le même schéma et le même chemin de migration.",
 "mem.db.4.k": "sqlite-vec",
 "mem.db.4.v": "Un backend vectoriel natif raccordé au chemin de rappel, utilisé lorsque l'extension sqlite-vec est présente.",
 "mem.db.note": "<b>Les sessions sont des données de premier ordre.</b> La bibliothèque de sessions liste, reprend, renomme et supprime les conversations — et en <b>forke</b> une à n'importe quel message vers une nouvelle branche, avec des vues complètes de l'arbre de forks, pour explorer des alternatives sans perdre le fil d'origine.",
 "onto.kicker": "ontobuild · pkg/ontology",
 "onto.title": "Un moteur d'ontologie <span class=\"accent\">natif</span>",
 "onto.sub": "La plupart des stacks greffent une base de données graphe distincte sur le côté. Jikji construit et sert les graphes de connaissances <b>à l'intérieur du binaire</b> — un moteur en Go pur qui dérive une ontologie de vos documents et y répond en SPARQL 1.1, sans aucun triple store externe à exploiter.",
 "onto.b.tag": "ontobuild — le moteur de construction",
 "onto.b.h2": "D'un corpus à une ontologie ancrée dans les faits",
 "onto.b.p": "Pointez-le vers un corpus : il en dérive le schéma et les faits — pas seulement des triplets, mais les classes et les relations qui les relient, validés au fil de leur arrivée.",
 "onto.b.1.label": "Construction émergente<span class=\"mono\">schema discovers itself</span>",
 "onto.b.1.p": "La construction émergente dérive les classes, les relations et les préfixes CURIE d'une ontologie à partir du matériau source lui-même, sans exiger de schéma préalable — avec des passes d'analyse facultatives pour approfondir la structure.",
 "onto.b.2.label": "Extraction &amp; synthèse<span class=\"mono\">documents → triples</span>",
 "onto.b.2.p": "Un codec d'extraction transforme les documents en triplets typés, et une passe de synthèse compose une structure de plus haut niveau par-dessus — pour que le graphe capture le sens, et pas seulement les mentions.",
 "onto.b.3.label": "Ancrage &amp; vérification<span class=\"mono\">stays clean</span>",
 "onto.b.3.p": "L'ancrage valide chaque nouvelle relation par rapport à son texte source avant de l'accepter, écarte les triplets hallucinés, et le linting natif préserve la cohérence interne de l'ontologie — ainsi, la qualité ne dérive pas à mesure que le graphe grandit.",
 "onto.b.4.label": "Incrémental &amp; idempotent<span class=\"mono\">grow, don't rebuild</span>",
 "onto.b.4.p": "Amorcez une construction à partir d'une ontologie existante et n'ajoutez que ce qui est nouveau — un accumulateur déduplique les triplets, si bien que des exécutions répétées sont idempotentes. Conçu pour se rafraîchir selon un calendrier via le cron <code>almanac</code>, et non pour être reconstruit de zéro.",
 "onto.b.cap": "Construisez ou rafraîchissez depuis la CLI — ancrez de nouveaux faits, approfondissez avec des passes d'analyse, faites grandir un graphe existant :",
 "onto.s.tag": "pkg/ontology — le moteur de requêtes",
 "onto.s.h2": "Servi en mémoire, interrogé en SPARQL",
 "onto.s.p": "Le graphe vit dans un store RDF en Go pur, au cœur du runtime. Les agents l'interrogent comme un outil, le planificateur s'en trouve enrichi et les opérateurs y accèdent via l'API — le tout sans base de données séparée.",
 "onto.s.1.h": "SPARQL 1.1, embarqué",
 "onto.s.1.p": "Un moteur SPARQL écrit de zéro — lexeur, parseur et évaluateur — répond aux SELECT avec patterns de graphe de base, FILTER, OPTIONAL, UNION, MINUS, BIND, VALUES, chemins de propriété, sous-requêtes et agrégation (GROUP BY / HAVING), avec des garde-fous sur la taille des résultats.",
 "onto.s.2.h": "Store RDF en Go pur",
 "onto.s.2.p": "Un store de triplets en mémoire et indexé, avec analyse et sérialisation TTL, gestion des préfixes et cycle de vie freeze/unload — pas de JVM, pas de sidecar, aucune base de données graphe externe à exploiter.",
 "onto.s.3.h": "Recherche sémantique &amp; reclassement",
 "onto.s.3.p": "L'outil <code>ontology.search</code> mêle la recherche dans le graphe à un reclassement sémantique fondé sur des embeddings, pour que la recherche s'appuie sur un sens structuré. Les embeddings sont optionnels (Jina, OpenAI ou Ollama) et reviennent au seul graphe lorsqu'ils sont désactivés.",
 "onto.s.4.h": "Il enrichit le planificateur",
 "onto.s.4.p": "Au-delà des faits, la couche <code>lexicon</code> porte des situations et des modèles de workflow qui injectent du contexte dans la boucle de l'agent — l'ontologie façonne ainsi la manière dont l'agent planifie, pas seulement ce qu'il peut consulter. Le tout cloisonné par tenant.",
 "onto.s.cap": "Interrogez le graphe en direct en SPARQL 1.1 — via les outils <span class=\"mono\">lexicon.query</span> / <span class=\"mono\">ontology</span> ou l'API :",
 "onto.s.note": "<b>Pourquoi le natif compte</b> — construire et servir le graphe dans le même binaire statique tient la promesse de l'indépendance à l'échelle : l'ontologie voyage avec le runtime, du portable au cluster, sans rien de plus à déployer ni à sécuriser.",
 "onto.h.tag": "Traitement hybride des données",
 "onto.h.h2": "Une ontologie posée sur vos données",
 "onto.h.p": "Un graphe de connaissances est le plus utile lorsqu'il se pose sur de vraies données opérationnelles. Jikji associe l'ontologie à un store relationnel gouverné, à des pipelines et à des caches — le modèle « ontologie sur les données » des plateformes de décision modernes, implémenté nativement au sein d'un runtime d'agents.",
 "onto.h.1.h": "Graphe et tables, ensemble",
 "onto.h.1.p": "L'ontologie est une couche sémantique posée sur le store relationnel de <code>galley</code> (SQLite, PostgreSQL ou MySQL). Les agents raisonnent sur les deux — le sens dans le graphe et les lignes en base — au cours d'une même exécution.",
 "onto.h.2.h": "Accès SQL gouverné",
 "onto.h.2.p": "Un outil SQL permet aux agents d'interroger les données, mais <code>sqlguard</code> impose une liste d'autorisation pour les instructions et les tables — en lecture seule par défaut — et <code>galley</code> injecte un prédicat tenant_id afin que chaque requête reste limitée à son propre locataire. L'analyse ne sort jamais du cadre de la politique.",
 "onto.h.3.h": "Pipelines &amp; mise en cache",
 "onto.h.3.p": "Importez et exportez des données via des outils de pipeline, et conservez les résultats intermédiaires dans des caches cloisonnés par tenant et un cache de réponses sémantique — pour que l'analyse répétée soit rapide et ne repaie pas deux fois le même travail.",
 "onto.h.4.h": "L'analyse dans la boucle",
 "onto.h.4.p": "Mettez tout cela ensemble et un agent peut extraire des lignes via du SQL gouverné, les recouper avec l'ontologie, mettre les intermédiaires en cache et raisonner sur le résultat — une couche de données polyvalente qui transforme les données opérationnelles en réponses.",
 "onto.h.5.h": "Data science et ML, dans la boucle",
 "onto.h.5.p": "Récupérez des lignes via du SQL gouverné, réutilisez-les depuis le cache, puis transmettez-les à un outil Python exécutant pandas, NumPy ou scikit-learn — l'analyse et la modélisation se déroulent au sein d'une même exécution de l'agent, pas à l'écart dans un notebook séparé.",
 "onto.h.6.h": "L'ontologie audite le système",
 "onto.h.6.p": "Modélisez votre propre système comme une ontologie : les composants sont des nœuds et <b>les invariants, des prédicats vérifiables</b> sur des observations en direct. Confronter mécaniquement une observation à son invariant produit une violation, matérialisée dans le graphe — si bien que « le système est sain » est une affirmation à prouver sur la base de zéro violation constatée, jamais autodéclarée.",
 "onto.h.f1": "Base SQL",
 "onto.h.f2": "Cache SQL",
 "onto.h.flow": "Interrogez une fois, réutilisez le résultat mis en cache, puis analysez-le avec la pile scientifique que vous fournissez dans le bac à sable — jikji est aussi à l'aise avec le traitement des données qu'avec la conversation.",
 "pn.enterprise": "Entreprise &amp; sécurité",
 "ent.kicker": "Gouverné comme une infrastructure",
 "ent.title": "Une gouvernance <span class=\"accent\">native</span>, pas rajoutée après coup",
 "ent.sub": "Multi-tenancy, autorisation, masquage, audit, traçage et quotas sont des modules au cœur du produit — pas des plugins ajoutés après une fuite. Jikji est conçu pour le jour où une plateforme d'agents devra rendre des comptes à la sécurité, à la conformité et à la finance.",
 "ent.perm.tag": "imprimatur · rubric · screen",
 "ent.perm.h2": "Identité, autorisation et plan de politique",
 "ent.perm.p": "L'identité, les décisions d'autorisation, le filtrage dynamique des politiques et la publication de services sont quatre préoccupations distinctes derrière quatre limites.",
 "ent.perm.1.h": "Multi-tenancy &amp; RBAC",
 "ent.perm.1.p": "Des principaux multi-locataires issus de clés d'API à portée définie, avec des portées <code>resource:action</code> et des jokers hiérarchiques — auxquels s'ajoutent des politiques de ressources/actions de type IAM (autoriser/refuser, jusqu'à un seul outil) que vous pouvez attacher à une clé et surcharger à l'exécution sans redémarrage. Un simulateur de politiques vous permet de valider et de tester un changement avant sa mise en production. L'authentification échoue en mode fermé : les principaux anonymes ne reçoivent jamais un accès complet, et les nouvelles clés exigent des portées explicites.",
 "ent.perm.2.h": "Plan de décision",
 "ent.perm.2.p": "Un plan d'autorisation dédié évalue le locataire, le principal, l'action et le contexte de l'outil pour rendre un <code>allow</code>, un <code>deny</code> ou un <code>ask</code> — et consigne chaque décision, avec un motif à la fois pour l'autorisation et pour le refus, dans une piste d'audit structurée.",
 "ent.perm.3.h": "Chaîne de filtres dynamique",
 "ent.perm.3.p": "Des filtres de requête composables avec des prédicats conditionnels <code>when</code> (heure, environnement, attributs de requête), des portes d'approbation, des appels de politique externe protégés par un disjoncteur, et des modes de permission <code>auto</code> / <code>ask</code> / <code>deny</code> — capturez la chaîne active dans un instantané et revenez à une version saine connue à l'exécution.",
 "ent.perm.4.h": "Approuvez ce que les agents exposent",
 "ent.perm.4.p": "Les agents peuvent définir leurs propres surfaces UI et API ; les opérateurs les listent, les approuvent ou les révoquent une par une depuis le plan de service — via l'API, <code>jikjictl service</code> ou le tableau de bord — le tout régi par le même chemin de politique que toute autre action.",
 "ent.perm.cap": "La politique est une donnée — les règles aboutissent à autoriser, demander ou refuser, et bloquent par défaut :",
 "ent.mt.tag": "Multitenancy &amp; personnalisation",
 "ent.mt.h2": "Un seul service, de multiples tenants, à chaque utilisateur le sien",
 "ent.mt.p": "Un modèle d'utilisateurs pensé pour l'entreprise est intégré d'emblée. Déployez un service par tenant, laissez les utilisateurs y accéder via des clés client à portée restreinte, et offrez à chacun un agent privé et personnalisé — sans faire tourner un déploiement distinct pour qui que ce soit.",
 "ent.mt.1.h": "Un tenant est une frontière de service",
 "ent.mt.1.p": "Chaque tenant possède ses propres clés, données, mémoire et politiques. Déployez un service par tenant — ou par équipe, client ou environnement — tous sur le même cluster, totalement isolés les uns des autres.",
 "ent.mt.2.h": "Chaque utilisateur est un principal à portée définie",
 "ent.mt.2.p": "Les utilisateurs accèdent à un service en tant que principals dotés de scopes, et une seule clé de service peut en porter de nombreux. Une identité actor sur chaque requête distingue un utilisateur final d'un autre, de sorte qu'ils restent séparés sans qu'il faille une clé par personne ; les scopes décident toujours, à chaque requête, de ce que chacun peut faire.",
 "ent.mt.3.h": "Une mémoire isolée par utilisateur",
 "ent.mt.3.p": "Le rappel et l'ingestion sont partitionnés par tenant <em>et</em> par acteur, et estampillés sur chaque exécution depuis le principal — ainsi un utilisateur ne voit jamais la mémoire d'un autre, même au sein du même service.",
 "ent.mt.4.h": "Des réponses hyper-personnalisées",
 "ent.mt.4.p": "Les faits propres à chaque utilisateur et son ontologie personnelle façonnent la manière dont l'agent lui répond — un contexte personnalisé injecté par principal, et non un seul et même prompt partagé par tous.",
 "ent.mt.eg": "<b>Un service, une clé, de nombreux clients.</b> Le client A et le client B accèdent tous deux au service <span class=\"mono\">asdf</span> via la même clé, mais chaque requête porte sa propre identité actor : leur mémoire, leur contexte et leur personnalisation restent ainsi séparés, et chacun bénéficie d'une expérience privée conçue rien que pour lui.",
 "ent.sec.tag": "Identifiants &amp; protection des données",
 "ent.sec.h2": "Secrets, masquage et défense contre l'injection",
 "ent.sec.1.h": "Coffre-fort &amp; OAuth",
 "ent.sec.1.p": "Un magasin d'identifiants AES-GCM (fichier ou adossé à galley) avec rotation et audit des accès, géré par CLI, API ou tableau de bord. Les fournisseurs peuvent utiliser des identifiants env, coffre-fort ou OAuth, avec connexion par appareil et rafraîchissement des jetons — et les clés en clair sont masquées à l'export de la configuration.",
 "ent.sec.2.h": "Masquage des données personnelles &amp; secrets",
 "ent.sec.2.p": "Le module <code>proof</code> détecte et masque de façon réversible les données personnelles et les secrets à l'aide de marqueurs stables, avant que le texte ne soit publié ou envoyé vers l'extérieur, puis rétablit les valeurs pour l'appelant — en gérant proprement les limites de fragments dans les réponses en streaming.",
 "ent.sec.3.h": "Garde anti-injection de prompt",
 "ent.sec.3.p": "Le contenu non fiable est mis en évidence et neutralisé, et le suivi de contamination bloque les outils sensibles dès qu'une exécution a ingéré des données externes — pour se défendre contre les tentatives de détournement d'instruction et de jailbreak.",
 "ent.sec.4.h": "Contrôle SSRF &amp; du trafic sortant",
 "ent.sec.4.p": "Le trafic HTTP sortant des contrôles de politique et des extensions injectées passe par des contrôles anti-SSRF face à des listes d'autorisation explicites, bloquant le loopback et les plages privées sauf autorisation délibérée.",
 "ent.pii.tag": "proof — PII &amp; secrets",
 "ent.pii.h2": "La fuite stoppée à la source",
 "ent.pii.p": "Sur les chemins d'exécution raccordés à <code>Proof</code>, les valeurs correspondant aux motifs <code>regex</code> intégrés, régionaux ou personnalisés activés peuvent être masquées avant le traitement couvert du fournisseur, de l'outil ou du journal. Les chemins de retour couverts peuvent restaurer les valeurs associées ; le mode drop omet volontairement cette restauration. Les formats non reconnus et les chemins hors de Proof restent hors de ce contrôle : l'opérateur doit configurer les motifs et vérifier chaque chemin de données.",
 "ent.pii.d1": "vos données",
 "ent.pii.d2": "masquage",
 "ent.pii.d3": "modèle · outil · journal",
 "ent.pii.d4": "restauration",
 "ent.pii.flow": "Sur un chemin <code>Proof</code> configuré, une valeur correspondant à un <code>regex</code> activé peut devenir un substitut stable comme <span class=\"mono\">[PII_EMAIL_1]</span>. Les valeurs non reconnues et les chemins hors de Proof passent sans modification.",
 "ent.pii.1.h": "Masqué avant de partir",
 "ent.pii.1.p": "Sur les chemins explicitement intégrés à <code>Proof</code>, les motifs <code>regex</code> activés masquent les entrées ou sorties d'outil correspondantes avant la frontière couverte de sortie ou de persistance. C'est une défense en profondeur : testez chaque chemin configuré et minimisez les données sensibles, car les regex ne détectent pas tous les formats.",
 "ent.pii.2.h": "Intact pour l'utilisateur réel",
 "ent.pii.2.p": "Des substituts réversibles et stables sont restaurés pour l'appelant, si bien que la vue de l'utilisateur final reste intacte — l'aller-retour de masquage lui est invisible, sans rien de tronqué ni de perdu.",
 "ent.pii.3.h": "Sûr en flux &amp; éphémère",
 "ent.pii.3.p": "Les substituts sont restaurés correctement, même à cheval sur les frontières des fragments de streaming, et la table des substituts est liée au locataire et jamais persistée — elle ne vit que le temps de la requête.",
 "ent.obs.tag": "Observabilité &amp; coûts",
 "ent.obs.h2": "Tout voir, tout tracer, tout plafonner",
 "ent.obs.1.h": "Traçage OpenTelemetry",
 "ent.obs.1.p": "Traces OTLP en gRPC ou HTTP avec propagation du contexte de trace W3C et échantillonnage en tête, identifiants de corrélation tout au long du chemin de requête et journaux d'accès structurés.",
 "ent.obs.2.h": "Métriques &amp; profilage",
 "ent.obs.2.p": "Un endpoint Prometheus <code>/metrics</code> avec une cardinalité de labels bornée, des métriques d'exécution et d'étape des agents, des compteurs de dispatch et des endpoints pprof pour le profilage en direct.",
 "ent.obs.3.h": "Limites d'usage &amp; quotas",
 "ent.obs.3.p": "Suivez les quotas des fournisseurs externes (fenêtres glissantes et hebdomadaires) et appliquez des quotas internes par locataire, avec des points de terminaison d'administration, des jauges, des panneaux de tableau de bord et <code>jikjictl provider usage</code>. Lorsque la fenêtre d'un fournisseur est atteinte (une limite de 5 heures ou une erreur 429), la répartition réessaie de façon durable une fois la limite levée, au lieu de faire échouer le travail.",
 "ent.obs.5.h": "Garde-fou de coût",
 "ent.obs.5.p": "Définissez des paliers de coût et des budgets par modèle qui alimentent un garde-fou de coût — il plafonne aussi les panneaux multi-modèles <code>trinity</code> afin qu'un ensemble ne puisse pas dépasser le budget. Gérez les paliers et les budgets avec <code>jikjictl cost</code>.",
 "ent.obs.4.h": "Débogage en direct, attachable à chaud",
 "ent.obs.4.p": "Attachez-vous à une session en cours via un terminal interactif reposant sur WebSocket (un PTY, sous Unix) pour l'observer et la piloter en direct. La trace d'étapes JSONL rejoue une exécution de bout en bout, et <code>/debug/pprof</code> profile le processus en cours d'exécution.",
 "ent.rob.tag": "Robustesse &amp; exploitation",
 "ent.rob.h2": "Conçu pour tenir le jour où tout va mal",
 "ent.rob.1.h": "Reprise &amp; durabilité",
 "ent.rob.1.p": "Points de reprise par étape et reprise exactly-once, nouvelle tentative sur SQLITE_BUSY et gestionnaires de baux distribués qui échouent bruyamment plutôt que de simuler la réussite.",
 "ent.rob.2.h": "Isolation des pannes",
 "ent.rob.2.p": "Disjoncteurs par fournisseur, files bornées avec baux de revendication et de validation, nouvelles tentatives avec délai progressif et vidange propre à l'arrêt.",
 "ent.rob.3.h": "Intégrité de la chaîne d'approvisionnement",
 "ent.rob.3.p": "Installations signées depuis la place de marché (Ed25519 ou HMAC) avec sommes de contrôle vérifiées, et un pare-feu de sortie qui se bloque par défaut si son filtre ne peut pas s'installer.",
 "ent.rob.4.h": "Canaux &amp; webhooks",
 "ent.rob.4.p": "Une interface d'adaptateur de canal modulaire pilote les exécutions d'agent depuis les plateformes de messagerie — un adaptateur Telegram aujourd'hui, conçu pour aller plus loin (Slack et au-delà) — avec en complément des webhooks entrants signés, des portées d'outils propres à chaque conversation, des listes d'autorisation et des limites de débit.",
 "ent.rob.5.h": "Configuration &amp; rechargement",
 "ent.rob.5.p": "Export de la configuration par l'opérateur et rechargement à chaud via API, CLI et tableau de bord, avec une analyse de configuration déterministe, validée et couverte par des tests.",
 "ent.rob.6.h": "Outils d'exploitation",
 "ent.rob.6.p": "<code>jikjictl</code> pour les identifiants, le RBAC, les politiques, les filtres, l'audit, le traçage, l'usage et la marketplace — plus un tableau de bord web qui ne stocke jamais les clés côté serveur : un playground avec instantanés, rollback et approbation d'inquiry sur place ; des vues de filtres avec badges de circuit breaker ; des politiques IAM avec le simulateur ; les surfaces du plan de service ; des panneaux d'usage ; et la gestion du coffre-fort.",
 "ent.cli.cap": "Pilotez l'ensemble depuis la CLI d'exploitation :",
 "ent.upd.tag": "Exploitation sans interruption",
 "ent.upd.h2": "Mettez-le à jour sans l'arrêter",
 "ent.upd.p": "Une plateforme qui fait tourner l'activité ne peut pas s'arrêter pour être reconfigurée. Jikji est conçu pour changer à chaud — se vider proprement, recharger la config sur place et déployer les mises à jour sur un cluster qui ne cesse jamais de servir.",
 "ent.upd.1.h": "Vidange en douceur",
 "ent.upd.1.p": "À l'arrêt, le nœud cesse d'accepter de nouvelles tâches, laisse les exécutions en cours se terminer, puis seulement sort — ainsi un redémarrage ou un redéploiement ne coupe jamais une session en plein vol.",
 "ent.upd.2.h": "Rechargement de config à chaud",
 "ent.upd.2.p": "Exportez et rechargez la config du runtime via l'API, la CLI ou le tableau de bord sans redémarrer — changez fournisseurs, filtres et politiques à chaud, avec un parsing déterministe et validé.",
 "ent.upd.3.h": "Mises à jour progressives via HA",
 "ent.upd.3.p": "Avec la HA activée, les contrôleurs partagent une même base de données et élisent un unique leader pour les planificateurs singletons, tandis que chaque nœud sert le trafic — vous mettez ainsi les nœuds à jour un par un et le cluster continue de tourner.",
 "tools.kicker": "sorts — le runtime des outils",
 "tools.title": "Les <span class=\"accent\">sorts</span> que la boucle compose",
 "tools.sub": "Les outils sont les caractères mobiles que Jikji met en place — un large catalogue intégré, plus tout ce que vous installez, chacun s'exécutant derrière un contrôle de politique et un bac à sable, en local ou sur un nœud distant.",
 "tools.cat.tag": "Le catalogue",
 "tools.cat.h2": "Des outils intégrés, prêts à l'emploi",
 "tools.cat.p": "Un agent qui travaille a besoin de bien plus qu'une zone de chat. Jikji embarque un large ensemble d'outils pour qu'un agent puisse lire, chercher, naviguer, interroger, analyser et agir dès sa première exécution.",
 "tools.cat.1.k": "Espace de travail",
 "tools.cat.2.k": "Web &amp; navigateur",
 "tools.cat.3.k": "Données",
 "tools.cat.3.v": "(géré par sqlguard)",
 "tools.cat.4.k": "Connaissances",
 "tools.cat.4.v": "(SPARQL)",
 "tools.cat.5.k": "Orchestration",
 "tools.cat.8.k": "Objectifs &amp; planification",
 "tools.cat.9.k": "Publication",
 "tools.cat.6.k": "Recherche &amp; compétences",
 "tools.cat.7.k": "Canaux",
 "tools.cat.7.v": "(Telegram)",
 "tools.cat.7.v2": "webhooks entrants",
 "tools.cat.note": "Chaque appel d'outil passe d'abord par le plan de politique <span class=\"mono\">rubric</span>, de sorte qu'un agent n'exécute jamais que ce que son tenant et ses portées autorisent.",
 "tools.fn.tag": "Étendez-le vous-même",
 "tools.fn.h2": "Une fonction est un outil",
 "tools.fn.p": "Pas besoin de recompiler pour ajouter une capacité. Écrivez une fonction Lua ou Python — ou un script Python complet —, publiez-la, et elle est enregistrée comme un outil de premier ordre à l'exécution, derrière le même contrôle de politique et le même bac à sable, exposable via MCP, exactement comme les outils intégrés. Python s'exécute au niveau de la fonction pour un assistant rapide, ou au niveau du script pour des tâches plus lourdes.",
 "tools.fn.cap": "Publiez-la sur le <span class=\"mono\">bookstore</span> et elle s'enregistre automatiquement — sans recompilation, avec vérification de signature facultative avant exécution.",
 "loop.t.tag": "Les outils — sorts",
 "loop.t.h2": "Un runtime d'outils en bac à sable",
 "loop.t.p": "Les outils sont les <span class=\"mono\">sorts</span> mobiles que la boucle met en place — intégrés ou installés, exécutés en local ou sur un nœud distant, toujours derrière une porte de politique et un bac à sable.",
 "loop.t.1.h": "Outils intégrés &amp; runners",
 "loop.t.1.p": "Lecture/recherche/liste/remplacement/écriture de fichiers, shell, recherche web, navigateur sans interface (onglets, extraction du DOM, sauvegarde de la source), lecteur web au contenu épuré et récupération de pages, outils d'ontologie et de canaux, et compétences. Les exécuteurs couvrent des sous-processus Python en bac à sable, un moteur Lua embarqué, des commandes locales et des nœuds distants.",
 "loop.t.2.h": "MCP, dans les deux sens",
 "loop.t.2.p": "Un client Model Context Protocol communique avec des serveurs stdio et enregistre leurs outils dans la boîte à outils. Un serveur expose les outils de Jikji à n'importe quel hôte MCP. Les appels d'outils sont relayés dans les deux sens, avec streaming.",
 "loop.t.3.h": "Bac à sable en défense en profondeur",
 "loop.t.3.p": "Espaces de noms Linux, Landlock, seccomp et RLIMITs imposés par le parent, plus plafonds cgroup v2. Modes réseau <code>none</code>, <code>loopback</code> ou <code>host</code> avec liste d'autorisation pour le trafic sortant — appliqués à la frontière des appels système, le tout se bloquant par défaut si le filtre ne peut pas s'installer.",
 "loop.t.4.h": "Nœuds d'outils distants",
 "loop.t.4.p": "Déportez l'exécution des outils sur des workers <code>jikji-tool-node</code> à travers un tunnel TLS <code>jikji-relay</code>, avec un catalogue partagé durable, des disjoncteurs par nœud et une bascule — sans toucher à l'agent.",
 "loop.t.5.h": "Place de marché &amp; signature",
 "loop.t.5.p": "Publiez des outils Lua ou Python sur la <code>bookstore</code>, installez-les et enregistrez-les automatiquement à l'exécution. Les installations peuvent exiger des signatures Ed25519 ou HMAC, avec vérification des sommes de contrôle avant qu'un outil ne s'exécute.",
 "loop.t.6.h": "Garde anti-injection de prompt",
 "loop.t.6.p": "Le contenu externe non fiable est mis en évidence par des marqueurs encadrés d'un nonce et neutralisé ; le suivi de contamination bloque les outils sensibles (shell, écriture, réseau) dès qu'une exécution a ingéré des données non fiables. Les signaux détectés comprennent les tentatives de détournement d'instruction et de jailbreak.",
 "tools.xr.note": "Les outils n'ont pas à s'exécuter là où l'agent pense — voir <a href=\"orchestration.html\">l'orchestration d'outils inter-régions</a> sur la page Orchestration.",
 "about.crumb": "À propos",
 "about.kicker": "Jikji Labs",
 "about.title": "À propos de <span class=\"accent\">Jikji Labs</span>",
 "about.sub": "Jikji Labs développe Jikji, une plateforme d'agents modulaire inspirée des caractères mobiles en métal. Nous pensons que l'infrastructure d'agents doit être composable, gouvernée et durable dès le premier jour, à l'image des caractères mobiles qui ont rendu l'édition fiable à grande échelle.",
 "about.p1": "<b>Jikji</b> est un binaire Go statique unique qui exécute une boucle d'agent déterministe, une orchestration multimodèle adaptative, un plan de mémoire apprenant, un moteur d'ontologie natif et une gouvernance d'entreprise, d'un ordinateur portable à un cluster multinœud.",
 "about.c.tag": "Contactez-nous",
 "about.c.h2": "Contacter l'équipe",
 "about.maint.k": "Mainteneur",
 "about.email.k": "E-mail",
 "about.li.k": "LinkedIn",
 "about.gh.k": "GitHub",
 "about.note": "Jikji Labs est un projet indépendant. Cette page décrit ce qui existe aujourd'hui dans le code ; les API et les frontières entre modules peuvent évoluer avant la première version stable.",
 "nav.usecases": "Cas d'usage",
 "uc.kicker": "exemples — un livre de motifs exécutables",
 "uc.title": "Ce que vous pouvez <span class=\"accent\">construire</span> avec Jikji",
 "uc.sub": "Chaque motif correspond à une configuration, des commandes ou des preuves dans le dépôt. Les mécanismes déterministes sont séparés des exécutions en direct dépendant du fournisseur, afin que vous puissiez voir exactement ce qui a été testé et ce qui dépend encore de votre environnement.",
 "uc.g1.tag": "Construire un agent",
 "uc.g1.h2": "D'un appel de chat à une exécution guidée par un objectif",
 "uc.g1.p": "Partez de là où vous êtes — un point de terminaison compatible OpenAI prêt à l'emploi — puis évoluez vers des exécutions guidées par objectif et un raisonnement multi-modèle, sans changer de pile.",
 "uc.chat.h": "Chat compatible OpenAI",
 "uc.chat.p": "Pointez un client OpenAI existant vers Jikji : <code>POST /v1/chat/completions</code>, sans streaming ou en flux SSE. Changez l'URL de base et gardez votre code.",
 "uc.run.h": "Exécutions d'agent guidées par objectif",
 "uc.run.p": "Transformez un objectif en une exécution avec points de contrôle et rejouable grâce à <code>jikjictl run</code> et <code>POST /v1/runs</code>, diffusée étape par étape — la boucle déterministe <code>forme</code>, pas une chaîne opaque.",
 "uc.multi.h": "Raisonnement multi-modèle",
 "uc.multi.p": "Lancez un débat d'essaim, une comparaison avec juge ou une boucle d'agent sur plusieurs modèles à la fois — retenez la meilleure réponse, ou faites-la vérifier par un panel.",
 "uc.tools.h": "Découvrir &amp; appeler des outils",
 "uc.tools.p": "Listez le catalogue d'outils de l'agent et invoquez n'importe lequel directement avec <code>POST /v1/tools/call</code> — les mêmes outils que ceux de la boucle, disponibles via l'API.",
 "uc.lua.h": "Outils Lua &amp; Python personnalisés",
 "uc.lua.p": "Enregistrez votre propre outil sous forme de script Lua ou de fonction Python <code>run(input)</code> et il rejoint le catalogue — sans recompilation, contrôlé comme n'importe quel outil intégré.",
 "uc.g2.tag": "Outils, données &amp; analyse",
 "uc.g2.h2": "Lire, interroger et calculer — sous contrôle d'une politique",
 "uc.g2.p": "Donnez à un agent de vraies capacités sans renoncer au contrôle : chaque fichier, requête et appel shell s'exécute derrière une politique par tenant et un bac à sable.",
 "uc.file.h": "Outils de fichiers du plan de travail",
 "uc.file.p": "Cantonnez un agent à un ensemble de racines et laissez-le lire, chercher, écrire et lister des fichiers — protégé par chemin, il ne s'échappe jamais du plan de travail que vous lui accordez.",
 "uc.sql.h": "Accès SQL gouverné",
 "uc.sql.p": "Exposez un outil SQL en lecture seule (SELECT) avec une politique d'accès en couches, par tenant — l'agent interroge les données qui lui sont autorisées, et rien d'autre.",
 "uc.data.h": "Pipeline de données façon Palantir",
 "uc.data.p": "Combinez une ontologie, une requête SQL en lecture seule (SELECT), un cache intermédiaire et une analyse <code>extension.python</code> (numpy/pandas) en un seul pipeline sous contrôle de KPI — données, cache et analyse dans une seule boucle.",
 "uc.code.h": "Codage &amp; débogage conscients des types",
 "uc.code.p": "Éditions par ancrage vérifiées par hachage, un contrôle <code>code.check</code> de niveau compilateur, renommage de symboles et tests shell — un agent de codage tenu à un KPI d'acceptation mesurable, pas à l'intuition.",
 "uc.g3.tag": "Objectifs &amp; orchestration",
 "uc.g3.h2": "Un travail au long cours qui survit à une panne",
 "uc.g3.p": "Structurez un travail ambitieux en objectifs mesurables et files durables, puis empilez les primitives sur un seul harnais récupérable.",
 "uc.goal.h": "Hiérarchie d'objectifs avec de vrais KPI",
 "uc.goal.p": "Construisez un arbre d'objectifs imbriqués avec des KPI mesurables (le motif « trombone ») : acceptation mécanique, preuves et un contrôle d'obsolescence observedGeneration, pour qu'une cible resserrée ne puisse pas être faussement satisfaite.",
 "uc.compose.h": "Mécanismes composables",
 "uc.compose.p": "Empilez les primitives : objectifs + une file de répartition + <code>trinity.ensemble</code> (multi-modèle sous contrôle de vérificateur) + <code>trinity.oracle</code> (contrôle de dérive), le tout sur un seul harnais durable.",
 "uc.queue.h": "Travail autonome piloté par file",
 "uc.queue.p": "Mettez en file des éléments de travail et lancez une boucle de worker qui vide la file puis se termine — ou attend indéfiniment avec <code>--keep-waiting</code>. Durable, sûre en réclamation, redémarrable.",
 "uc.almanac.h": "Tâches autonomes planifiées",
 "uc.almanac.p": "Des tâches cron et à intervalle qui émettent des commandes d'orchestrateur, des outils, du travail en file ou des notifications — au plus une fois et à l'épreuve des pannes au fil des redémarrages.",
 "uc.runners.h": "De nombreuses surfaces d'exécution, un seul contrôle",
 "uc.runners.p": "Routez les outils sur des surfaces nommées — shell local, python, navigateur, nœuds d'outils distants avec bacs à sable docker ou ssh — le tout sous une seule chaîne de contrôle, du portable au cluster.",
 "uc.g4.tag": "Recherche &amp; connaissance",
 "uc.g4.h2": "Fondé, cité, vérifié de manière adverse",
 "uc.g4.p": "Faites qu'un agent cite les pages capturées et dérive les violations à partir de preuves — des réponses que vous pouvez vérifier, pas des suppositions assurées.",
 "uc.web.h": "Recherche web fondée",
 "uc.web.p": "Cherchez, ouvrez, lisez et enregistrez des sources, puis reliez chaque affirmation à une page capturée avec <code>research.source</code> — cité à de vraies pages, pas aux données d'entraînement.",
 "uc.onto.h": "Revue mécanique d'invariants",
 "uc.onto.p": "Affirmez des prédicats, fournissez des observations mesurées et <b>dérivez</b> les violations en mode fail-closed — en matérialisant un graphe de contradictions au lieu de demander à un modèle de « vérifier ».",
 "uc.paper.h": "Rédaction vérifiée de manière adverse",
 "uc.paper.p": "Rédigez un article d'ingénierie où chaque affirmation est un KPI : un contrôle d'ambiguïté, des affirmations d'objectif, des sources web, <code>system.review</code> et une passe d'ensemble/oracle <code>trinity</code> avant qu'il ne tienne.",
 "uc.kg.h": "Ontologie &amp; graphe de connaissances natifs",
 "uc.kg.p": "Construisez et servez des ontologies nativement — TTL, SPARQL via <code>lexicon.query</code> et <code>ontology.search</code> sémantique — une couche de connaissances sur laquelle la boucle raisonne directement.",
 "uc.g5.tag": "Intégrer &amp; interopérer",
 "uc.g5.h2": "Parlez tous les protocoles d'agent",
 "uc.g5.p": "Exposez Jikji comme un serveur que d'autres systèmes savent déjà appeler — MCP, ACP, A2A — et connectez les canaux où vivent vos utilisateurs.",
 "uc.mcp.h": "Serveur MCP",
 "uc.mcp.p": "Exposez les outils de Jikji comme un serveur Model Context Protocol via stdio ou HTTP — n'importe quel client MCP les pilote directement.",
 "uc.acp.h": "ACP via stdio et HTTP",
 "uc.acp.p": "Utilisez JSON-RPC via stdio pour les clients ACP locaux, ainsi qu’un manifeste HTTP et une interface d’invocation pour les intégrations distantes.",
 "uc.a2a.h": "Registre agent-à-agent",
 "uc.a2a.p": "Découvrez et surveillez des agents dans le registre A2A via gRPC — le substrat pour des agents qui se trouvent et s'appellent entre eux.",
 "uc.tg.h": "Bot Telegram → exécutions d'agent",
 "uc.tg.p": "Lancez un bot Telegram qui transforme chaque message en une exécution d'agent — réponses en flux, commandes slash, là où vos utilisateurs se trouvent déjà.",
 "uc.codex.h": "gpt-5.5 sur un abonnement ChatGPT",
 "uc.codex.p": "Pilotez gpt-5.5 via un abonnement ChatGPT avec <code>codex-responses</code> et OAuth par appareil — quota d'abonnement, sans facture d'API séparée.",
 "uc.g6.tag": "Gouverner &amp; multi-tenant",
 "uc.g6.h2": "Exploitez-le comme un service, pour de nombreux utilisateurs",
 "uc.g6.p": "Servez des tenants isolés depuis un seul déploiement : portées par clé, frontières d'outils en refus par défaut, et une place de marché pour distribuer ce que vous construisez.",
 "uc.rbac.h": "Clés &amp; portées par tenant",
 "uc.rbac.p": "Émettez des clés d'API, des portées et des liaisons de rôle par tenant avec <code>jikjictl rbac</code> — un seul déploiement, de nombreux utilisateurs isolés, chacun avec sa propre portée.",
 "uc.perm.h": "RBAC aux frontières des outils",
 "uc.perm.p": "Exigez des portées par outil, refusez par défaut et déployez l'autorisation en toute sûreté via un parcours par étapes <code>observe → warn → enforce</code> avec préflight — resserrez sans casser le trafic.",
 "uc.market.h": "Publier &amp; installer des paquets",
 "uc.market.p": "Empaquetez un outil ou un agent enregistré, publiez-le sur la place de marché et installez-le sur un autre tenant — signé, versionné, une seule commande pour l'adopter.",
 "uc.close.p": "<b>Chaque exemple est une pièce mobile.</b> Le vrai levier, c'est de les assembler — une hiérarchie d'objectifs qui pilote une file de répartition, traitée par un conseil sous contrôle de vérificateur, citant des sources web et contrôlée par une revue mécanique. Prélevez celles dont vous avez besoin, réglez-les au plus juste, et imprimez.",
 "uc.ratelimit.h": "Franchissez la limite d'usage sans broncher",
 "uc.ratelimit.p": "Vous atteignez la limite d'usage d'un fournisseur ou d'un abonnement ChatGPT (429/529) ? Jikji lit la véritable fenêtre de réinitialisation — y compris les fenêtres 5-hour et hebdomadaire de codex — et reprend au lieu d'échouer. Une exécution interactive patiente avec <code>--wait-on-rate-limit</code> (plafonnée par <code>--max-wait</code>, 6h par défaut) ; les agents dispatchés et les exécutions de plan reprennent sans surveillance depuis leur dernier point de contrôle dès que la fenêtre se réinitialise (<code>rate_limit_resume: park</code>) — aucun client n'a besoin de rester connecté.",
 "uc.backbone.h": "La colonne vertébrale intelligente de votre application",
 "uc.backbone.p": "Faites de Jikji le moteur de raisonnement dédié d'une application distincte : votre application garde la maîtrise de ses données et de ses outils en lecture seule, envoie un scénario déterministe par POST à <code>/v1/runs</code>, et Jikji rappelle ces outils via un sous-processus MCP déclaré sous <code>sorts.mcp_servers</code> — chaque appel étant contrôlé et audité. Votre application n'importe jamais Jikji et n'embarque aucun framework d'agent ; elle reste un simple client HTTP.",
 "uc.council.h": "Un conseil inter-fournisseurs que votre CLI de code ne peut convoquer seule",
 "uc.council.p": "Une CLI de code (Claude Code, Codex) a bien ses propres sous-agents — mais ils relèvent tous d'un seul fournisseur. Pour une décision à fort enjeu — un audit de sécurité, un choix d'architecture — elle raccorde un Jikji en cours d'exécution via <code>/v1/mcp</code> et soumet la question à un conseil inter-fournisseurs, encadré par des politiques, audité et voté par des vérificateurs (<code>trinity.ensemble</code>) : des modèles de fournisseurs distincts répondent, un panel vote ACCEPT/REVISE, puis un synthétiseur fusionne les réponses retenues. S'y ajoutent <code>trinity.oracle</code> (contrôle de dérive) et <code>agent.spawn</code>. Le détour par MCP ne vaut que pour les décisions lourdes de conséquences, jamais pour le codage courant.",
 "hero.kicker.current": "Runtime d'agent d'entreprise · Version Go statique · GPL par défaut",
 "hero.offer.current": "La plateforme d'agent d'entreprise, composée en caractères métalliques.",
 "proof.tag": "Preuve, pas une diapositive produit",
 "proof.h": "Les exemples sont des contrats exécutables décrivant le comportement de Jikji.",
 "proof.p": "Le dépôt fournit des scénarios exécutables, une configuration de production, des artefacts fonctionnels et des vérifications protégées de fournisseurs en direct. Ils documentent le chemin d'un test echo local à un conseil de cinq fournisseurs, un worker durable ou un déploiement multi-locataire renforcé. Les affirmations dépendant d'un fournisseur ou d'un environnement sont étiquetées comme telles.",
 "proof.cta": "Ouvrir le registre d'exemples",
 "proof.live": "Preuve en direct",
 "proof.worked": "Artefact fonctionnel",
 "proof.deterministic": "Déterministe",
 "proof.operator": "Chemin opérateur",
 "proof.cli": "Un CLI de codage appelle un conseil inter-fournisseurs via HTTP MCP ; l'exécution enregistrée contient cinq candidats et cinq votes de vérificateurs.",
 "proof.trinity": "Réponses indépendantes, synthèse et un panel contradictoire ACCEPT/REVISE avec le résultat conservé pour inspection.",
 "proof.queue": "Comportement durable de revendication, bail, achèvement et redémarrage démontré sans recourir à l'avis d'un modèle.",
 "proof.ops": "Auth, TLS, politique, audit, rédaction, sauvegardes, readiness et observabilité assemblés en une checklist de déploiement à sécurité par défaut.",
 "img.usecases.alt": "Livre de motifs ouvert entouré d'artefacts de vérificateur, d'une file d'attente durable, d'un graphe de tâches, d'une topologie de déploiement et de sortie de commande",
 "img.jikjicode.alt": "Atelier de codage gravé reliant la structure du code source, les modifications de précision, la vérification, les outils protégés et une impression finale",
 "ledger.tag": "Preuves sélectionnées",
 "ledger.h2": "Partez d'un chemin fonctionnel, pas d'un cadre vide",
 "ledger.p": "Ce catalogue distingue les chemins d'intégration pris en charge, les mécanismes éprouvés, les références opérateur et les preuves de recherche. Chaque lien ouvre le mécanisme public ou la preuve opérationnelle correspondante sur ce site.",
 "ledger.th.example": "Exemple",
 "ledger.th.scope": "Ce que couvre la preuve",
 "ledger.th.tier": "Preuve · niveau de support",
 "ledger.cli.scope": "HTTP MCP depuis un CLI de codage vers un <code>trinity.ensemble</code> à cinq fournisseurs, Oracle et des exécutions enfants durables.",
 "ledger.cli.tier": "Exécution fonctionnelle en direct · chemin d'intégration",
 "ledger.trinity.scope": "Diffusion des candidats, synthèse, vote des vérificateurs et réponse acceptée conservée pour inspection.",
 "ledger.trinity.tier": "Artefact fonctionnel en direct · mécanisme",
 "ledger.taskgraph.scope": "Sous-agents durables conscients des dépendances, vagues concurrentes et sérialisation des conflits de fichiers.",
 "ledger.taskgraph.tier": "Artefact fonctionnel déterministe · mécanisme",
 "ledger.queue.scope": "Revendications de file d'attente durable, baux, achèvement et comportement de redémarrage du worker.",
 "ledger.queue.tier": "Artefact fonctionnel déterministe · mécanisme",
 "ledger.prod.scope": "Contrôles de sécurité par défaut : auth, TLS, politique, audit, rédaction, récupération et télémétrie pour qualifier dans votre environnement.",
 "ledger.prod.tier": "Checklist + configuration · référence opérateur",
 "ledger.ha.scope": "PostgreSQL partagé, élection du leader, readiness, drainage et topologie multi-nœuds.",
 "ledger.ha.tier": "Configuration + procédure · référence de déploiement",
 "ledger.rho.scope": "Propositions de harnais rétrospectif inspirées de RHO admises par les portes mécaniques de Pareto, qualité, Oracle, preuve et approbation opérateur.",
 "ledger.rho.tier": "Porte testée unitairement · adaptateur expérimental ; non prouvé",
 "ledger.eval.scope": "Un banc d'essai contrôlé qui attribue tâche, modèle, harnais, environnement, scoreur, échecs et métriques comparables.",
 "ledger.eval.tier": "Méthode + tâches fonctionnelles · pas un résultat de benchmark",
 "ledger.self.scope": "Une expérience limitée et retenue qui a falsifié sa sonde prometteuse : les directives génériques et la recherche automatique n'ont pas battu la référence.",
 "ledger.self.tier": "Résultat négatif contrôlé et sous-puissant · recherche",
 "ledger.foresight.scope": "Répétition de persona ancrée dans l'ontologie avec provenance et portes de vérificateur ; exploration structurée, jamais prédiction.",
 "ledger.foresight.tier": "Mécanisme en direct partiel · la démo complète a atteint une limite de débit documentée",
 "ledger.relay.scope": "Adhésion signée Ed25519, identifiants d'amorçage à usage unique et limités, baux renouvelables et reconnexion par clé stable pour les nœuds d'outils distants.",
 "ledger.relay.tier": "Tests E2E/race, redémarrage durable/multi-contrôleur, cycle de vie opérateur, HTTPS, politique/limitation par locataire, audit Galley à sécurité par défaut et bascule explicite entre seeds",
 "img.arch.alt": "Atelier modulaire gravé montrant les stations d'entrée, politique, modèle, outil et état durable connectées",
 "plate.arch.title": "CHEMIN DE REQUÊTE",
 "plate.arch.meta": "EN PROCESSUS D'ABORD · HTTP / gRPC PRÊT",
 "plate.arch.s1h": "press + imprimatur",
 "plate.arch.s1p": "L'entrée authentifie le locataire et construit un principal délimité.",
 "plate.arch.s2h": "rubric + compositor",
 "plate.arch.s2p": "La politique décide ; la session et l'exécution durable sont assemblées.",
 "plate.arch.s3h": "typebackbone + sorts",
 "plate.arch.s3p": "Les modèles et les outils régis s'exécutent derrière des interfaces stables.",
 "plate.arch.s4h": "galley + proof",
 "plate.arch.s4p": "L'état, les liens, les charges utiles sécurisées pour l'audit et les preuves persistent.",
 "plate.arch.cap": "Chaque limite est utilisable d'abord comme une API Go en processus et conçue pour se déplacer derrière un protocole de service standard sans réécrire la règle métier.",
 "img.loop.alt": "Harnais d'agent circulaire gravé déplaçant l'état durable à travers les stations de plan, action, observation et point de contrôle",
 "loop.research.tag": "Recherche harnais",
 "loop.research.h2": "Plusieurs boucles délimitées, mesurées séparément",
 "loop.research.p": "Jikji mappe les idées de recherche sur des primitives durables existantes au lieu de traiter « l'auto-amélioration » comme une boucle magique. Chaque mécanisme a une limite de preuve séparée.",
 "loop.research.stack.h": "Boucles de contrôle empilées",
 "loop.research.stack.p": "Les boucles d'agent, de vérification, événementielles, d'escalade et d'approbation humaine peuvent composer, tandis que le noyau Go et les hooks Lua maintiennent leurs rôles d'application explicites.",
 "loop.research.rho.h": "Propositions inspirées de RHO",
 "loop.research.rho.p": "Les traces passées peuvent proposer une directive de harnais, mais les portes mécaniques de Pareto, qualité, Oracle, preuve et approbation de l'opérateur décident si elle peut être essayée. Elle ne s'applique jamais automatiquement.",
 "loop.research.limit.h": "Limite mesurée, pas une promesse",
 "loop.research.limit.p": "L'exemple de recherche auto-améliorante contrôlée n'a pas battu la référence et était sous-dimensionné. De meilleurs modèles futurs pourraient rendre le mécanisme plus utile, mais seule une mesure A/B retenue peut établir une amélioration.",
 "loop.research.note": "Niveau de preuve : tests de porte déterministes plus artefacts de recherche. Les déploiements de modèles en direct restent dépendants du fournisseur ; l'objectif actuel de taux de réussite inclut un proxy de cohérence Oracle et ne doit pas être décrit comme une résolution de tâche mesurée.",
 "img.tools.alt": "Catalogue d'outils gravé passant par une porte de politique vers des exécuteurs locaux, navigateur, conteneur et distants",
 "plate.tools.title": "EXÉCUTION D'OUTIL",
 "plate.tools.meta": "UN CHEMIN DE POLITIQUE, PLUSIEURS EXÉCUTEURS",
 "plate.tools.s1h": "Catalogue",
 "plate.tools.s1p": "Les outils intégrés, les outils MCP et les extensions installées exposent des schémas typés.",
 "plate.tools.s2h": "Porte de politique",
 "plate.tools.s2p": "Le locataire, le principal, l'action, les arguments et l'environnement produisent autoriser, refuser ou demander.",
 "plate.tools.s3h": "Exécuteur + bac à sable",
 "plate.tools.s3p": "L'exécution locale, Lua, Python, navigateur, conteneur, SSH ou nœud distant reste délimitée.",
 "plate.tools.s4h": "Preuve + audit",
 "plate.tools.s4p": "Les sorties sont nettoyées, attribuées, mesurées et intégrées dans l'exécution en tant qu'observations.",
 "plate.tools.cap": "La surface d'exécution peut changer sans contourner les contrôles d'autorisation, de rédaction, de délai d'attente ou d'audit.",
 "img.orch.alt": "Presses candidates indépendantes gravées convergeant vers la synthèse, les jauges de vérification et une presse de libération finale",
 "plate.orch.title": "ENSEMBLE TRINITÉ",
 "plate.orch.meta": "RÉPONSES DIVERSES · PORTE ADVERSARIALE",
 "plate.orch.s1h": "Candidats indépendants",
 "plate.orch.s1p": "Des modèles configurés distincts répondent sans se voir les uns les autres.",
 "plate.orch.s2h": "Synthèse",
 "plate.orch.s2p": "Un synthétiseur concilie les preuves, les désaccords et les alternatives viables.",
 "plate.orch.s3h": "Panneau de vérification",
 "plate.orch.s3p": "Des juges distincts votent ACCEPT ou REVISE par rapport à l'objectif et à la Rubrique.",
 "plate.orch.s4h": "Publier ou réviser",
 "plate.orch.s4p": "La porte accepte ou lance une autre révision limitée ; Oracle vérifie la dérive de trajectoire séparément.",
 "plate.orch.cap": "La diversité des fournisseurs est une configuration, pas une garantie : un conseil significatif nécessite des familles de modèles véritablement distinctes et des identifiants valides.",
 "orch.evidence.tag": "Preuve de harnais",
 "orch.evidence.h2": "La politique d'orchestration peut évoluer ; la qualité doit encore être mesurée",
 "orch.evidence.p": "Le coordinateur, le vérificateur et l'optimiseur inspiré de RHO sont des mécanismes séparés. Une proposition qui passe l'admission est sûre à évaluer, pas prouvée meilleure.",
 "orch.evidence.1h": "Admission mécanique d'abord",
 "orch.evidence.1p": "Les mises à jour de harnais dominées, dérivées ou mécaniquement pires sont rejetées avant qu'une préférence de modèle ne puisse briser une véritable égalité.",
 "orch.evidence.2h": "Porte de publication humaine",
 "orch.evidence.2p": "Une directive admissible est déposée en attente d'approbation. Un opérateur la révise avant une injection additive et plafonnée dans les exécutions ultérieures.",
 "orch.evidence.3h": "Comparaison sur données retenues",
 "orch.evidence.3p": "Les harnais de base et modifiés nécessitent le même ensemble de tâches, environnement, scoreur et métriques attribuées. Un gain nul ou négatif signifie rejeter la directive.",
 "img.memory.alt": "Système de mémoire d'archives gravé persistant, liant, consolidant et récupérant un ensemble compact d'enregistrements",
 "plate.memory.title": "MÉMOIRE DURABLE",
 "plate.memory.meta": "LIMITÉ AU LOCATAIRE · BASÉ SUR GALLEY",
 "plate.memory.s1h": "Observer",
 "plate.memory.s1p": "La boucle de forme émet des événements typés, des faits, des liens et des actions mémoire explicites.",
 "plate.memory.s2h": "Persister dans Galley",
 "plate.memory.s2p": "SQLite ou un backend SQL partagé enregistre l'état durable avec des migrations.",
 "plate.memory.s3h": "Consolider dans Plate",
 "plate.memory.s3p": "L'extraction, la déduplication, les liens de graphe et la consolidation en arrière-plan affinent le rappel.",
 "plate.memory.s4h": "Récupérer + compacter",
 "plate.memory.s4p": "La recherche hybride sélectionne la mémoire pertinente tandis que la compaction respecte la fenêtre de tokens.",
 "plate.memory.cap": "La durabilité est mécanique ; la qualité d'extraction et de classement reste dépendante du modèle et de l'embedding et doit être évaluée sur votre corpus.",
 "img.ontology.alt": "Moteur gravé transformant des documents source en un graphe de connaissances lié, une requête structurée et une violation mise en évidence",
 "plate.ontology.title": "CHEMIN DE CONNAISSANCES",
 "plate.ontology.meta": "CORPUS VERS GRAPHE VÉRIFIABLE",
 "plate.ontology.s1h": "Corpus + observations",
 "plate.ontology.s1p": "Les documents, les données relationnelles et les faits système mesurés entrent via des outils gouvernés.",
 "plate.ontology.s2h": "Graphe de lexique",
 "plate.ontology.s2p": "Les entités, relations, situations, prédicats et provenance deviennent des enregistrements limités au locataire.",
 "plate.ontology.s3h": "SPARQL + recherche",
 "plate.ontology.s3p": "Les requêtes de graphe structurées et la récupération sémantique exposent des vues complémentaires.",
 "plate.ontology.s4h": "Révision + action",
 "plate.ontology.s4p": "L'évaluation d'invariants matérialise des violations pour que l'agent puisse raisonner et remédier.",
 "plate.ontology.cap": "Le graphe enregistre la provenance et prend en charge les prédicats mécaniques ; l'extraction d'entités générée nécessite encore une évaluation de qualité spécifique au corpus.",
 "onto.foresight.tag": "Prévision fondée sur l'ontologie",
 "onto.foresight.h2": "Répéter un futur ; ne jamais prétendre le prédire",
 "onto.foresight.p": "Le bac à sable de prévision enregistre les acteurs du scénario dans le graphe, dérive un petit ensemble de personas de parties prenantes, exécute des réactions limitées et demande à un ensemble contrôlé par vérificateur un rapport mappé à la provenance.",
 "onto.foresight.1h": "Entrées fondées",
 "onto.foresight.1p": "Chaque branche de rapport doit remonter à une réaction de persona, un fait de graphe enregistré et une graine source. La synthèse non étayée est révisée plutôt qu'acceptée.",
 "onto.foresight.2h": "Simulation limitée",
 "onto.foresight.2p": "La conception de référence utilise quatre à six personas sur un ou deux tours afin que le coût reste limité et que chaque réaction reste vérifiable.",
 "onto.foresight.3h": "Niveau de preuve honnête",
 "onto.foresight.3p": "Les étapes de spawn/drain durables et du graphe ont été exercées en direct, y compris un minimal child terminé. La démo complète à trois personas a atteint une limite de débit documentée d'un seul worker avant la synthèse.",
 "onto.foresight.note": "Il s'agit d'une exploration structurée de scénarios, et non d'une prévision, d'une décision ou d'une affirmation d'exactitude. La prose du modèle est non déterministe ; la reproductibilité couvre l'orchestration et la provenance.",
 "img.enterprise.alt": "Ligne de contrôle d'entreprise gravée déplaçant une identité délimitée à travers les étapes de politique, de vérification, de refus et d'audit",
 "plate.enterprise.title": "CHEMIN DE CONTRÔLE",
 "plate.enterprise.meta": "ÉCHEC FERMÉ PAR COUCHE",
 "plate.enterprise.s1h": "Identité",
 "plate.enterprise.s1p": "Imprimatur résout le locataire, l'acteur, les portées et les identifiants en un principal.",
 "plate.enterprise.s2h": "Autorisation",
 "plate.enterprise.s2p": "Rubric évalue le principal, l'action, l'outil, les arguments et l'environnement.",
 "plate.enterprise.s3h": "Vérification",
 "plate.enterprise.s3p": "Les PII, secrets et charges utiles non sécurisées sont détectés ou expurgés avant l'exécution sortante.",
 "plate.enterprise.s4h": "Audit + télémétrie",
 "plate.enterprise.s4p": "Les décisions et les résultats deviennent des preuves tenant-compte du locataire sans secrets bruts.",
 "plate.enterprise.cap": "La préparation à la production dépend d'une configuration explicite : la terminaison TLS, le stockage externe des secrets, les clés de sauvegarde, la haute disponibilité de la base de données et le routage des alertes sont des responsabilités de l'opérateur.",
 "notice.english": "Cette page reste faisant autorité en anglais. La locale sélectionnée s'applique à la navigation partagée ; ne vous fiez pas à une traduction non officielle pour les termes juridiques.",
 "notice.english.ops": "Cette page reste faisant autorité en anglais. La locale sélectionnée s'applique à la navigation partagée ; suivez le runbook anglais lors d'un incident.",
 "nav.code": "jikjicode",
 "jc.kicker": "jikjicode — l’agent de codage",
 "jc.title": "Un agent de codage qui <span class=\"accent\">édite comme un compilateur</span>",
 "jc.sub": "jikjicode est une CLI autonome d’agent de codage fondée sur la boucle déterministe de Jikji. Elle effectue des modifications précises ancrées par hachage, comprend votre code au moyen du compilateur — et non par correspondance de chaînes — et exécute vos compilations et tests, localement sur votre machine ou par délégation à un serveur Jikji.",
 "jc.cmd.tag": "Un seul binaire, tous les workflows",
 "jc.cmd.h2": "S’exécute là où vous travaillez",
 "jc.cmd.p": "Un seul binaire <span class=\"mono\">jikjicode</span>. Pointez-le vers n’importe quel modèle compatible OpenAI : il exécute la boucle de l’agent dans le processus sur votre espace de travail, ou confiez l’exécution entière à un serveur Jikji afin que son RBAC et son sandbox la délimitent. Interactif dans un terminal, automatisable partout ailleurs.",
 "jc.cmd.1.k": "Local",
 "jc.cmd.1.v": "Par défaut, la boucle <code>forme</code> s’exécute dans le processus avec votre modèle et l’ensemble d’outils de codage sur votre espace de travail.",
 "jc.cmd.2.k": "Distant",
 "jc.cmd.2.v": "Déléguez l’exécution entière à un serveur Jikji via <code>/v1/runs</code> ; les portées et le sandbox du serveur la délimitent.",
 "jc.cmd.3.k": "Interactif et ponctuel",
 "jc.cmd.3.v": "Une TUI plein écran dans un terminal, une REPL ligne par ligne hors terminal et <code>jikjicode exec</code> pour une tâche unique, avec des événements JSONL via <code>--json</code> pour l’automatisation.",
 "jc.cmd.4.k": "Configuration",
 "jc.cmd.4.v": "<code>jikjicode init</code> génère la structure d’une configuration ; <code>jikjicode doctor</code> vérifie votre modèle et votre environnement avant de commencer.",
 "jc.edit.tag": "MODIFICATIONS PRÉCISES",
 "jc.edit.h2": "Des modifications qui refusent d’agir sur un fichier périmé",
 "jc.edit.p": "Le mode d’échec des agents de codage consiste à modifier un texte dont ils se souviennent mal. jikjicode ancre chaque changement dans le contenu réellement présent sur le disque.",
 "jc.edit.1.h": "Modifications ancrées par hachage",
 "jc.edit.1.p": "<code>file.edit</code> lie chaque changement à un hachage de contenu et à une ancre de ligne. Si le fichier a changé, la modification est refusée — et non appliquée silencieusement au mauvais endroit — tandis qu’une échelle de correspondance tolérante et la récupération d’ancre permettent de retrouver la cible lorsque les lignes se décalent.",
 "jc.edit.2.h": "Correctifs atomiques sur plusieurs fichiers",
 "jc.edit.2.p": "<code>file.apply_patch</code> applique un changement portant sur plusieurs fichiers comme une seule unité et annule l’ensemble en cas d’échec partiel, sans laisser le dépôt à moitié modifié.",
 "jc.edit.3.h": "Diagnostic automatique après chaque modification",
 "jc.edit.3.p": "Les modifications JSON et YAML sont vérifiées syntaxiquement en cours de processus. Lorsque l'exécution hôte explicite est activée, les diagnostics de packages Go peuvent s'exécuter après une modification et réinjecter les échecs dans le même tour.",
 "jc.edit.4.h": "Compatible Unicode",
 "jc.edit.4.p": "Les modifications et la mise en correspondance des identifiants tiennent compte des runes : les sources multioctets et les identifiants non ASCII sont donc traités correctement plutôt que corrompus à une limite d’octet.",
 "jc.ci.tag": "INTELLIGENCE DU CODE",
 "jc.ci.h2": "Il lit le code au moyen du compilateur",
 "jc.ci.p": "Pas de « grep en espérant que ça marche ». Les outils Go sensibles aux types utilisent la véritable chaîne d'outils ; les plans structurels couvrent plus de 200 langages ; et les manifestes de language-server approuvés par l'opérateur ajoutent des symboles multilingues et des graphes d'appels lorsque l'exécution hôte complète est explicitement activée.",
 "jc.ci.1.k": "Vérification de types",
 "jc.ci.1.v": "diagnostics de niveau compilateur pour Go (go/packages), afin que « cela compile » soit vérifié et non présumé",
 "jc.ci.2.k": "Navigation",
 "jc.ci.2.v": "— sensible aux types pour Go (go/types)",
 "jc.ci.3.k": "Renommage",
 "jc.ci.3.v": "renommage sûr, multifichier et sensible aux types pour Go",
 "jc.ci.4.k": "Plan",
 "jc.ci.4.v": "— AST complet pour Go et analyse des définitions fondée sur un lexer (semblable à ctags) pour plus de 200 autres langages",
 "jc.ci.5.k": "Multilangage via LSP",
 "jc.ci.5.v": "— symboles bornés et résultats appelant/appelé issus d'un language server approuvé par l'opérateur, activés paresseusement selon l'extension de fichier sous accès hôte complet explicite",
 "jc.ci.note": "Les processus language-server sont traités comme du code hôte de confiance : les manifestes exigent un chemin absolu contrôlé par l'opérateur, les cadres et les résultats sont bornés, les échappements via liens symboliques de l'espace de travail sont rejetés, et les identifiants du fournisseur sont supprimés de l'environnement enfant.",
 "jc.run.tag": "COMPILER, TESTER, LIVRER",
 "jc.run.h2": "Il exécute votre projet sous le contrôle que vous définissez",
 "jc.run.p": "Un agent de codage incapable d’exécuter les tests ne fait que deviner. jikjicode exécute de véritables commandes de compilation et de test, avec un contrôle des risques et une approbation humaine facultative que vous maîtrisez.",
 "jc.run.1.h": "Shell portable",
 "jc.run.1.p": "<code>shell.run</code> exécute vos commandes de compilation et de test sur plusieurs plateformes ; sous Unix, dans leur propre groupe de processus afin qu’un délai d’expiration arrête tout l’arbre, avec troncature du début et de la fin de la sortie pour qu’un journal bruyant ne sature jamais le contexte.",
 "jc.run.2.h": "Sandbox fondé sur les risques",
 "jc.run.2.p": "Une politique configurable — <code>read-only</code>, <code>workspace-write</code> ou <code>danger-full-access</code> — délimite les risques d'outils autorisés. En local, l'écriture est par défaut limitée à l'espace de travail ; les commandes hôtes, les language servers et l'accès réseau requièrent une activation explicite. Les exécutions distantes sont encadrées par la politique du serveur.",
 "jc.run.3.h": "Demander avant d’agir",
 "jc.run.3.p": "Une couche d'approbation facultative (<code>--ask</code>) place un humain dans la boucle pour les actions que le bac à sable autorise déjà. Une approbation absente ou non interactive échoue de manière sûre ; une approbation ne remplace jamais un refus du bac à sable.",
 "jc.run.4.h": "Documentation et tâches à portée de main",
 "jc.run.4.p": "<code>web.fetch</code> récupère de la documentation sous le contrôle du sandbox, et un suivi <code>todo</code> maintient une modification en plusieurs étapes organisée d’un tour à l’autre.",
 "jc.run.note": "Même boucle, surface plus riche : jikjicode est la face dédiée au codage de la boucle <a href=\"agent-loop.html\">forme</a> et se combine avec les <a href=\"use-cases.html\">exemples d’orchestrateur-exécuteur et de codage</a>.",
 "plate.code.title": "CYCLE DE MODIFICATION",
 "plate.code.meta": "ANCRÉ, VÉRIFIÉ, RÉVERSIBLE",
 "plate.code.s1h": "Comprendre",
 "plate.code.s1p": "La vérification de types, les symboles et un graphe d’appels lisent le code au moyen du compilateur et des serveurs de langage.",
 "plate.code.s2h": "Modifier",
 "plate.code.s2p": "Les modifications ancrées par hachage et les correctifs atomiques sur plusieurs fichiers refusent d’agir sur un fichier périmé.",
 "plate.code.s3h": "Vérifier",
 "plate.code.s3p": "Chaque modification qui change le contenu est revérifiée, et les compilations et tests s’exécutent au moyen d’un shell portable.",
 "plate.code.s4h": "Délimiter",
 "plate.code.s4p": "Un sandbox fondé sur les risques, avec approbation facultative, contrôle ce que l’agent peut exécuter.",
 "plate.code.cap": "La même boucle déterministe forme, dotée d’un ensemble d’outils orienté codage : chaque modification est ancrée, chaque commande est délimitée."
};
